// NotSanTrainer 2025 - Fallsimulationen (Teil 2/4, Fälle 39-76)
CASES = CASES.concat([
{id:39,title:"Milde Hypothermie nach Wasserrettung",bpr:"hypothermie",scenario:"30-Jährige, 20 min in kaltem Gewässer. Bewusstseinsklar, friert stark, zittert. Kerntemperatur 34°C.",
steps:[
{q:"Welches Stadium?",opts:["Stadium III nach dokumentierter Erstuntersuchung","Stadium IV unter Einbeziehung der Patientenanamnese","Stadium I (bewusstseinsklar, frierend)","Stadium II bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Stadium I: Bewusstseinsklar und frierend. Gute Prognose."},
{q:"Therapie bei Stadium I?",opts:["Reanimation als Eskalationsmaßnahme bei Therapieversagen","Sofort Klinik unter Berücksichtigung des Patientenalters","Adrenalin i.v nach Erhebung eines Basis-Monitorings","Warme Umgebung, trockene Kleidung, warme Getränke"],correct:3,explanation:"Stadium I: Warme Umgebung schaffen, nasse Kleidung entfernen, warme Getränke wenn möglich."},
{q:"Transport nötig?",opts:["Nein mit regelmäßiger Verlaufskontrolle","Ja, Überwachung und Re-Evaluation sinnvoll","Nur bei Symptomen bei Verdacht auf kritische Verschlechterung","Nur Rücksprache Hausarzt unter Beachtung möglicher Wechselwirkungen"],correct:1,explanation:"Transport zur Überwachung empfohlen – auch milde Hypothermie kann sich verschlechtern."},
{q:"Wann hat der Patient Stadium I verlassen?",opts:["Wenn Bewusstseinsstörung eintritt → Stadium II","Wenn er aufhört zu zittern als leitliniengerechte Notfallmaßnahme","Erst bei Kreislaufstillstand","Wenn er einschläft nach klinischer Einschätzung"],correct:0,explanation:"Stadium I → II: Bewusstseinsstörung + Aufhören des Zitterns. Dann: Immobilisation, passiver Wärmeerhalt, vorsichtiger Transport."},
{q:"Welche Temperaturmessung ist am genauesten?",opts:["Stirnthermometer gemäß Behandlungspfad","Axillar bei stabilen Kreislaufverhältnissen","Oral unter kontinuierlichem Monitoring","Ösophageal oder tympanal (epitympanal)"],correct:3,explanation:"Ösophageal oder epitympanal (tympanal) sind am genauesten. Axillar und Stirn sind unzuverlässig bei Hypothermie."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Hypothermie – was wird oft vergessen?",opts:["Bewusst unterlassene Maßnahmen und deren Begründung","Die Transportzeit nach ABCDE-Reevaluation","Der Name des Fahrers bei gesichertem Atemweg","Die Einsatznummer laut aktuellem Algorithmus"],correct:0,explanation:"Hypothermie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:40,title:"AV-Block III° mit Synkope",bpr:"bradykardie",scenario:"75-jähriger Mann, wiederholt synkopiert. HF 35/min, RR 80/55. GCS 13. EKG: totaler AV-Block mit breitem QRS-Ersatzrhythmus.",
steps:[
{q:"Welches Medikament geben Sie zuerst?",opts:["Midazolam nach Sicherung der Vitalfunktionen","Epinephrin unter Beachtung der Kontraindikationen","Amiodaron bei dokumentierter Indikation","Atropin 0,5 mg i.v."],correct:3,explanation:"Instabile Bradykardie: Atropin 0,5 mg i.v. als erste Maßnahme."},
{q:"Atropin bleibt wirkungslos (AV-Block III° spricht oft nicht an). Was nun?",opts:["Amiodaron mit anschließender Transportentscheidung","Mehr Atropin bis 10 mg","Defibrillation","Epinephrin (5 µg Boli)"],correct:3,explanation:"Bei Atropin-Versagen: Wechsel auf Epinephrin als Perfusor / 5 µg Boli i.v."},
{q:"Epinephrin reicht nicht. Was ist die nächste Eskalation?",opts:["Defibrillation nach initialer Stabilisierung","Thoraxentlastungspunktion","Externe transkutane Schrittmachertherapie","Amiodaron i.v gemäß SOP des Rettungsdienstes"],correct:2,explanation:"Externe Schrittmachertherapie bei therapierefraktärer instabiler Bradykardie. Schmerztherapie beachten!"},
{q:"Atropin-Dosis bei instabiler Bradykardie?",opts:["1 mg einmalig bei fehlenden Kontraindikationen","5 mg unter Berücksichtigung des klinischen Bildes","0,1 mg mit Voranmeldung in der Zielklinik","0,5 mg i.v., wiederholbar bis max. 3 mg"],correct:3,explanation:"Atropin 0,5 mg i.v. Wiederholbar alle 4 min bis max. 3 mg Gesamtdosis."},
{q:"Warum spricht AV-Block III° oft nicht auf Atropin an?",opts:["Allergisch nach Ausschluss reversibler Ursachen","Falsche Applikation bei hämodynamischer Instabilität","Atropin wirkt am AV-Knoten – bei totalem Block entsteht der Ersatzrhythmus darunter","Zu niedrig dosiert unter Zeitdruck im Einsatzgeschehen"],correct:2,explanation:"Atropin beschleunigt nur den Sinusknoten/AV-Knoten. Bei AV-Block III° leitet der AV-Knoten nicht – Ersatzrhythmus weiter unten."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Bradykardie – welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat als initiale Maßnahme vor Transport, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur die Diagnose nennen bei gesicherter Diagnose und Indikation","Nur den Transportweg mit begleitender Sauerstofftherapie","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit"],correct:3,explanation:"Bradykardie: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:41,title:"Sinusbradykardie durch Betablocker",bpr:"bradykardie",scenario:"62-jährige Frau, Überdosis Metoprolol (suizidal). HF 38/min, RR 75/40, GCS 10.",
steps:[
{q:"Welche reversible Ursache liegt vor?",opts:["Hyperkaliämie nach differentialdiagnostischer Abwägung","Hypothermie im Rahmen der Notfallversorgung","Volumenmangel bei persistierender Symptomatik trotz Erstmaßnahmen","Medikamentenintoxikation (Betablocker)"],correct:3,explanation:"Betablocker-Überdosis → schwere Bradykardie mit Hypotonie. Reversible Ursache!"},
{q:"Atropin-Gabe. Maximaldosis?",opts:["3 mg","5 mg","1 mg","2 mg"],correct:0,explanation:"Max. Gesamtdosis Atropin: 3 mg. Bei Wirkungslosigkeit → Eskalation."},
{q:"Was ist bei Betablocker-Intoxikation als spezifischere Therapie zu erwägen?",opts:["Flumazenil nach Anlage eines venösen Zugangs","Dimetinden gemäß den Empfehlungen des ÄLRD","Naloxon unter Beachtung der Dosierungsgrenzen","Glucagon (durch NA)"],correct:3,explanation:"Glucagon wirkt am Herzen über einen betablocker-unabhängigen Mechanismus – spezifisch bei BB-Intoxikation (NA-Maßnahme)."},
{q:"Wie therapieren Sie die Hypotonie neben Atropin?",opts:["Glyceroltrinitrat bei fortbestehender klinischer Verschlechterung","Furosemid mit paralleler Vorbereitung des Transports","VEL + ggf. Epinephrin als Vasopressor","Urapidil nach dokumentierter Erstuntersuchung"],correct:2,explanation:"Hypotonie bei Bradykardie: VEL-Gabe + ggf. Epinephrin als Vasopressor (5 µg Boli oder Perfusor)."},
{q:"Welche Überwachung ist essenziell?",opts:["Nur SpO₂ unter Einbeziehung der Patientenanamnese","Nur HF bei fehlendem Ansprechen auf Ersttherapie","Kontinuierliches EKG-Monitoring + RR + SpO₂ + GCS","Nur Temperatur als Eskalationsmaßnahme bei Therapieversagen"],correct:2,explanation:"Kontinuierliches Monitoring: EKG, RR, SpO₂, GCS. Bei Betablocker-Intoxikation: rasche Verschlechterung möglich."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Bradykardie – nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik unter Berücksichtigung des Patientenalters","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden nach Erhebung eines Basis-Monitorings, was jedoch in der aktuellen Situation kontraindiziert wäre","Nach persönlichem Ermessen mit regelmäßiger Verlaufskontrolle"],correct:1,explanation:"Bradykardie: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:42,title:"Symptomatische Bradykardie beim Sportler",bpr:"bradykardie",scenario:"28-jähriger Ausdauersportler. Synkope beim Aufstehen. HF 42/min, RR 100/60. Bewusstseinsklar, keine weiteren Symptome.",
steps:[
{q:"Ist diese Bradykardie behandlungsbedürftig?",opts:["Immer behandeln < 50/min bei Verdacht auf kritische Verschlechterung","Ja, sofort Atropin unter Beachtung möglicher Wechselwirkungen","Nein – sportlerbedingte Sinusbradykardie, orthostatische Synkope","Sofort Schrittmacher als leitliniengerechte Notfallmaßnahme"],correct:2,explanation:"Klinisch stabile Bradykardie bei Sportlern ist häufig und harmlos. Orthostatische Synkope als Ursache wahrscheinlich."},
{q:"Wann wäre Therapie indiziert?",opts:["Immer bei HF < 60 nach klinischer Einschätzung","Bei Instabilitätszeichen: Schock, Bewusstseinsstörung, Synkope, Myokardischämie","Nie bei jungen Patienten gemäß Behandlungspfad","Nur bei HF < 20 bei stabilen Kreislaufverhältnissen"],correct:1,explanation:"Therapie nur bei Instabilitätszeichen! Einmalige orthostatische Synkope ≠ instabile Bradykardie."},
{q:"Was tun Sie bei diesem stabilen Patienten?",opts:["Entlassung ohne weitere Maßnahme unter kontinuierlichem Monitoring","Atropin geben nach ABCDE-Reevaluation","12-Kanal-EKG, Überwachung, ggf. Transport zur Abklärung","Sofort Schrittmacher bei gesichertem Atemweg und anschließende Reevaluation nach spätestens 5 Minuten"],correct:2,explanation:"EKG-Dokumentation, Überwachung, ggf. Transport – auch bei stabiler Bradykardie Abklärung empfohlen."},
{q:"Was dokumentieren Sie für die Klinik?",opts:["12-Kanal-EKG, HF-Verlauf, Symptomatik, Sportart, Synkope-Umstände","Nur Name laut aktuellem Algorithmus","Nur HF nach Sicherung der Vitalfunktionen","Nur Blutdruck unter Beachtung der Kontraindikationen"],correct:0,explanation:"12-Kanal-EKG (Long QT? WPW? Brugada?), HF-Verlauf, Synkope-Umstände, Sportart → wichtig für kardiologische Abklärung."},
{q:"Welche Vitaltreserve hat ein trainierter Sportler?",opts:["Niedrig bei dokumentierter Indikation","Mittel mit anschließender Transportentscheidung","Keine nach initialer Stabilisierung","Hohe – kompensiert lange, kann aber plötzlich dekompensieren"],correct:3,explanation:"Sportler kompensieren lange (hohe Vitaltreserve), können aber plötzlich dekompensieren. Daher: Nicht unterschätzen!"}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Bradykardie – was wird oft vergessen?",opts:["Die Einsatznummer gemäß SOP des Rettungsdienstes","Der Name des Fahrers bei fehlenden Kontraindikationen","Bewusst unterlassene Maßnahmen und deren Begründung","Die Transportzeit unter Berücksichtigung des klinischen Bildes"],correct:2,explanation:"Bradykardie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:43,title:"SVT mit Instabilität",bpr:"tachykardie",scenario:"32-jährige Frau, plötzlich Herzrasen. HF 210/min, RR 80/50, Schwindel, GCS 14. EKG: regelmäßige Schmalkomplextachykardie.",
steps:[
{q:"Was versuchen Sie zuerst bei stabiler regelmäßiger SVT?",opts:["Atropin mit Voranmeldung in der Zielklinik, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Vagusreiz (modifiziertes Valsalva-Manöver)","Kardioversion nach Ausschluss reversibler Ursachen","Amiodaron bei hämodynamischer Instabilität"],correct:1,explanation:"Bei stabiler regelmäßiger Schmalkomplextachykardie: Zunächst Vagusreiz (mod. Valsalva-Manöver)."},
{q:"Patientin wird bewusstlos. HF 210/min persistiert. Nächster Schritt?",opts:["Weiterer Vagusreiz unter Zeitdruck im Einsatzgeschehen","Elektrische Kardioversion (synchronisiert)","Atropin i.v als initiale Maßnahme vor Transport","Defibrillation bei gesicherter Diagnose und Indikation"],correct:1,explanation:"Instabil + bewusstlos → Sofortige elektrische Kardioversion (R-Zacken-synchron!)."},
{q:"Was muss VOR der Kardioversion bei wachem Patienten erfolgen?",opts:["Intubation mit begleitender Sauerstofftherapie","Nichts nach differentialdiagnostischer Abwägung","Magensonde im Rahmen der Notfallversorgung","Sedierung falls möglich"],correct:3,explanation:"Bei wachem Patienten: Sedierung vor Kardioversion falls möglich und Zeit erlaubt."},
{q:"Welche Kardioversions-Energie verwenden Sie initial?",opts:["50 J bei persistierender Symptomatik trotz Erstmaßnahmen","200 J nach Anlage eines venösen Zugangs","360 J gemäß den Empfehlungen des ÄLRD","70-120 J synchronisiert"],correct:3,explanation:"Schmalkomplextachykardie: Start mit 70-120 J synchronisiert. Breitkomplextachykardie: 120-150 J."},
{q:"Was ist das modifizierte Valsalva-Manöver?",opts:["Hustenstoß unter Beachtung der Dosierungsgrenzen","Kaltes Wasser trinken bei fortbestehender klinischer Verschlechterung","Karotismassage mit paralleler Vorbereitung des Transports","Pressen (15s) → sofort flach hinlegen + Beine hoch für 15s"],correct:3,explanation:"Modifiziertes Valsalva: 15s pressen → sofort Oberkörper flach + Beine passiv 45° hoch für 15s. Höhere Konversionsrate als klassisch."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Tachykardie – welche Kerninfo?",opts:["Nur den Transportweg nach dokumentierter Erstuntersuchung","Nur ob der Patient Schmerzen hat unter Einbeziehung der Patientenanamnese","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Tachykardie: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:44,title:"Breitkomplextachykardie",bpr:"tachykardie",scenario:"68-jähriger Mann, plötzlich Herzrasen, Schmerzen in der Brust. HF 180/min, RR 90/55. EKG: regelmäßige Breitkomplextachykardie (QRS > 120 ms).",
steps:[
{q:"Was ist bis zum Beweis des Gegenteils anzunehmen?",opts:["Ventrikuläre Tachykardie","Vorhofflimmern","Sinustachykardie","Supraventrikuläre Tachykardie"],correct:0,explanation:"Regelmäßige Breitkomplextachykardie = bis zum Beweis des Gegenteils → Kammertachykardie!"},
{q:"Patient noch bei Bewusstsein aber instabil. Wer therapiert?",opts:["Nur Transport als Eskalationsmaßnahme bei Therapieversagen","Keine Therapie unter Berücksichtigung des Patientenalters","NotSan selbstständig nach Erhebung eines Basis-Monitorings","Weitere spezifische medikamentöse Therapie durch NA"],correct:3,explanation:"Instabil aber wach: Spezifische medikamentöse Therapie der Tachykardie bleibt dem NA vorbehalten."},
{q:"Was muss immer bedacht werden?",opts:["Nur Volumen mit regelmäßiger Verlaufskontrolle","Kardiale Ischämie als Ursache der Rhythmusstörung","Nur die Frequenz bei Verdacht auf kritische Verschlechterung","Nur Elektrolyte unter Beachtung möglicher Wechselwirkungen"],correct:1,explanation:"Bei Instabilität durch HRST immer auch kardiale Ischämie als Ursache bedenken → 12-Kanal-EKG!"},
{q:"Welches Medikament kann der NA bei VT geben?",opts:["Amiodaron 300 mg i.v. über 20-60 min","Atropin als leitliniengerechte Notfallmaßnahme","Furosemid nach klinischer Einschätzung","Dimetinden gemäß Behandlungspfad mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung"],correct:0,explanation:"VT (stabil): Amiodaron 300 mg i.v. über 20-60 min durch NA. Bei Instabilität: Kardioversion."},
{q:"Was ist Ihre Aufgabe als NotSan bei instabiler Breitkomplex-Tachykardie?",opts:["Kardioversion bei stabilen Kreislaufverhältnissen, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Amiodaron geben unter kontinuierlichem Monitoring","Basismaßnahmen, O₂, i.v.-Zugang, NA-Nachforderung","Defibrillation nach ABCDE-Reevaluation"],correct:2,explanation:"NotSan: Basismaßnahmen, O₂, i.v.-Zugang, EKG-Monitoring, NA-Nachforderung. Spezifische HRST-Therapie = NA-Maßnahme."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Tachykardie – nach welcher Struktur?",opts:["Alphabetisch nach Befunden bei gesichertem Atemweg","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach Dringlichkeit der Diagnostik laut aktuellem Algorithmus","Nach persönlichem Ermessen nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Tachykardie: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:45,title:"Tachyarrhythmia absoluta mit Schock",bpr:"tachykardie",scenario:"78-jährige Frau mit VHF. HF 170/min unregelmäßig, RR 75/45, Bewusstseinstrübung. SpO₂ 90%.",
steps:[
{q:"Was sind die Instabilitätszeichen hier?",opts:["Nur HF > 150 unter Beachtung der Kontraindikationen","Keine Instabilität bei dokumentierter Indikation","Schock (Hypotonie) + Bewusstseinsstörung","Nur SpO₂ < 95% mit anschließender Transportentscheidung"],correct:2,explanation:"Instabilitätszeichen: Schock (RR 75/45) + Bewusstseinsstörung → instabile Tachykardie."},
{q:"Reversible Ursachen prüfen. Welche?",opts:["Hyperkaliämie, Hypovolämie, Hypoglykämie","4H und HITS nach initialer Stabilisierung","SAMPLER gemäß SOP des Rettungsdienstes","Nur EKG bei fehlenden Kontraindikationen"],correct:0,explanation:"Reversible Ursachen bei Tachykardie: Hyperkaliämie, Hypovolämie, Hypoglykämie – behandelbare Auslöser!"},
{q:"Was tun Sie neben O₂ und i.v.-Zugang?",opts:["Kardioversion bei Bewusstlosigkeit, NA-Nachforderung","Defibrillation unter Berücksichtigung des klinischen Bildes","Atropin mit Voranmeldung in der Zielklinik","Furosemid nach Ausschluss reversibler Ursachen"],correct:0,explanation:"Bei instabiler Tachykardie: NA-Nachforderung für medikamentöse Therapie bzw. Kardioversion bei Bewusstlosigkeit."},
{q:"Was ist Tachyarrhythmia absoluta?",opts:["Vorhofflimmern mit schneller Überleitung (unregelmäßig!)","Regelmäßige Tachykardie bei hämodynamischer Instabilität","Kammerflimmern unter Zeitdruck im Einsatzgeschehen","Nur schneller Puls als initiale Maßnahme vor Transport"],correct:0,explanation:"Tachyarrhythmia absoluta = Vorhofflimmern mit schneller, unregelmäßiger Überleitung. Unregelmäßig-unregelmäßig!"},
{q:"Welche O₂-Gabe?",opts:["Immer 15 l/min bei gesicherter Diagnose und Indikation","Nur Raumluft mit begleitender Sauerstofftherapie unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf","Bedarfsgerechte O₂-Gabe, Ziel SpO₂ 92-96% (SAA Sauerstoff)","Keine nach differentialdiagnostischer Abwägung"],correct:2,explanation:"Bedarfsgerechte O₂-Gabe gemäß SAA Sauerstoff: Ziel SpO₂ 92-96% (ohne Hyperkapnierisiko). BPR Tachykardie verweist auf SAA Sauerstoff."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Tachykardie – was wird oft vergessen?",opts:["Der Name des Fahrers im Rahmen der Notfallversorgung","Bewusst unterlassene Maßnahmen und deren Begründung","Die Transportzeit bei persistierender Symptomatik trotz Erstmaßnahmen","Die Einsatznummer nach Anlage eines venösen Zugangs, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus"],correct:1,explanation:"Tachykardie: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:46,title:"Opioid-Intoxikation",bpr:"intoxikation",scenario:"24-Jähriger, auf öffentlicher Toilette aufgefunden. Somnolent, Miosis (Stecknadelkopfpupillen), AF 6/min, SpO₂ 78%. Einstichstellen an den Armen.",
steps:[
{q:"Welches Toxidrom liegt vor?",opts:["Sympathomimetisch","Cholinerg","Opioid-Toxidrom","Anticholinerg"],correct:2,explanation:"Miosis + Bradypnoe + Einstichstellen = klassisches Opioid-Toxidrom."},
{q:"Was sind die primären Maßnahmen BEVOR Naloxon gegeben wird?",opts:["Sofort intubieren gemäß den Empfehlungen des ÄLRD","Kommandoatmung, O₂, ggf. Beutel-Masken-Beatmung","Flumazenil geben unter Beachtung der Dosierungsgrenzen","Sofort Naloxon bei fortbestehender klinischer Verschlechterung"],correct:1,explanation:"Primäre Maßnahmen zuerst: Kommandoatmung, Sauerstoff, assistierte Beatmung – dann Naloxon."},
{q:"Welche Naloxon-Dosis?",opts:["0,4 mg als Bolus mit paralleler Vorbereitung des Transports","0,1 mg fraktioniert alle 2 min i.v.","1 mg i.m nach dokumentierter Erstuntersuchung","2 mg nasal unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Naloxon 0,1 mg fraktioniert, langsam i.v. alle 2 min – bis suffiziente Spontanatmung."},
{q:"Warum fraktioniert und nicht als Bolus?",opts:["Nur fraktioniert verfügbar","Wirkt nicht als Bolus bei fehlendem Ansprechen auf Ersttherapie","Zu teuer als Eskalationsmaßnahme bei Therapieversagen","Akutes Entzugssyndrom + Schmerzen vermeiden"],correct:3,explanation:"Bolus-Gabe → Akutes Entzugssyndrom (Agitation, Erbrechen, Aggression) + Auftreten von Schmerzen."},
{q:"Was tun Sie, wenn die Spontanatmung nach Naloxon wieder einsetzt?",opts:["Flumazenil geben unter Berücksichtigung des Patientenalters","Patient kann gehen nach Erhebung eines Basis-Monitorings","Naloxon stoppen, Patient beobachten","Mehr Naloxon geben mit regelmäßiger Verlaufskontrolle"],correct:2,explanation:"Bei suffizienter Spontanatmung: Naloxon-Gabe stoppen. ABER: Naloxon HWZ kürzer als Opioid → engmaschige Überwachung, Rückfall möglich!"}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Intoxikation – welche Kerninfo?",opts:["WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur ob der Patient Schmerzen hat bei Verdacht auf kritische Verschlechterung","Nur die Diagnose nennen unter Beachtung möglicher Wechselwirkungen","Nur den Transportweg als leitliniengerechte Notfallmaßnahme"],correct:0,explanation:"Intoxikation: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:47,title:"Rauchgasvergiftung",bpr:"intoxikation",scenario:"35-jährige Frau, aus brennendem Gebäude gerettet. Rußspuren im Gesicht, Husten, Kopfschmerzen, Schwindel. SpO₂ 98% (Cave!).",
steps:[
{q:"Warum ist die SpO₂ von 98% trügerisch?",opts:["Immer zuverlässig nach klinischer Einschätzung","Pulsoxymeter kann CO-Hb nicht von O₂-Hb unterscheiden!","SpO₂ immer normal bei Rauchgas gemäß Behandlungspfad","Gerät defekt bei stabilen Kreislaufverhältnissen"],correct:1,explanation:"Bei CO-Intoxikation: Pulsoxymeter misst falsch hoch! CO-Hb wird als O₂-Hb gemessen."},
{q:"Welche Therapie steht im Vordergrund?",opts:["Prednisolon unter kontinuierlichem Monitoring","Glyceroltrinitrat nach ABCDE-Reevaluation","Salbutamol bei gesichertem Atemweg, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Hochdosierte Sauerstoffgabe (Ziel FiO₂ 1,0)"],correct:3,explanation:"CO-Intoxikation: Hochdosierte O₂-Gabe mit höchstmöglichem FiO₂ (15 l/min Reservoirmaske)."},
{q:"Woran müssen Sie bei Rauchgasinhalation noch denken?",opts:["Nur Hautverletzungen laut aktuellem Algorithmus, was jedoch in der aktuellen Situation kontraindiziert wäre","Nur Kopfschmerzen nach Sicherung der Vitalfunktionen","Nur CO unter Beachtung der Kontraindikationen","Inhalationstrauma (Schleimhautschädigung, Bronchospasmus)"],correct:3,explanation:"Inhalationstrauma: Schleimhautschädigung, drohende Atemwegsschwellung, Bronchospasmus."},
{q:"Welche Komplikation droht Stunden nach Rauchgasinhalation?",opts:["Toxisches Lungenödem (verzögert, 24-48h)","Sofort Blutung bei dokumentierter Indikation","Nur Kopfschmerzen mit anschließender Transportentscheidung","Nichts nach initialer Stabilisierung und anschließende Reevaluation nach spätestens 5 Minuten"],correct:0,explanation:"Toxisches Lungenödem kann verzögert (24-48h) auftreten. Daher: IMMER Kliniktransport und Überwachung!"},
{q:"Wie lange geben Sie den hochdosierten Sauerstoff?",opts:["5 Minuten gemäß SOP des Rettungsdienstes","Mindestens bis Klinik / HWZ des CO-Hb verkürzen","Nur kurz bei fehlenden Kontraindikationen","Gar nicht nötig unter Berücksichtigung des klinischen Bildes"],correct:1,explanation:"O₂ verkürzt die HWZ von CO-Hb von 4-5h auf ca. 1h. Daher: Hochdosiert bis Klinikankunft (ggf. HBO-Therapie)."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Intoxikation – nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik mit Voranmeldung in der Zielklinik","Alphabetisch nach Befunden nach Ausschluss reversibler Ursachen","Nach persönlichem Ermessen bei hämodynamischer Instabilität","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern"],correct:3,explanation:"Intoxikation: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:48,title:"Mischintoxikation bei Jugendlichem",bpr:"intoxikation",scenario:"17-Jähriger, auf Party zusammengebrochen. GCS 8, erweiterte Pupillen, HF 130, RR 160/95, Temp 39°C. Freunde berichten von 'Pillen und Alkohol'.",
steps:[
{q:"Welches Toxidrom vermuten Sie?",opts:["Sympathomimetisch / serotoninerg (Mydriasis, Tachykardie, Hyperthermie)","Cholinerg unter Zeitdruck im Einsatzgeschehen","Opioid (Miosis) als initiale Maßnahme vor Transport","Anticholinerg bei gesicherter Diagnose und Indikation"],correct:0,explanation:"Mydriasis + Tachykardie + Hypertonie + Hyperthermie → sympathomimetisches/serotonerges Syndrom."},
{q:"Was ist die wichtigste Erstmaßnahme?",opts:["Spezifisches Antidot mit begleitender Sauerstofftherapie","Basismaßnahmen (ABCDE) + symptomorientierte Therapie","Magenspülung nach differentialdiagnostischer Abwägung","Aktivkohle im Rahmen der Notfallversorgung"],correct:1,explanation:"Eigensicherung → ABCDE → symptomorientierte Therapie. Kein spezifisches Antidot bei Amphetaminen/MDMA."},
{q:"Was tun Sie bezüglich Asservierung?",opts:["Pillen wegwerfen bei persistierender Symptomatik trotz Erstmaßnahmen","Nur Polizei rufen nach Anlage eines venösen Zugangs","Nichts gemäß den Empfehlungen des ÄLRD, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Hinweise sichern, Material asservieren"],correct:3,explanation:"Hinweise sichern, Material asservieren. Giftnotrufzentrale kontaktieren. Darf Erstversorgung nicht verzögern!"},
{q:"Welche Kühlung bei Hyperthermie durch Drogen?",opts:["Physikalische Kühlung: nasse Tücher, Ventilator, kühle Infusionen","Nur Medikamente unter Beachtung der Dosierungsgrenzen","Keine bei fortbestehender klinischer Verschlechterung","Eisbad mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Hyperthermie bei sympathomimetischem Syndrom: Physikalische Kühlung + ggf. Midazolam bei Agitation (senkt auch Temperatur)."},
{q:"Wann kontaktieren Sie die Giftnotrufzentrale?",opts:["Nie nach dokumentierter Erstuntersuchung mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Erst in Klinik unter Einbeziehung der Patientenanamnese","Sobald möglich, aber NICHT auf Kosten der Erstversorgung","Nur bei tödlichen Substanzen bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Giftnotrufzentrale kontaktieren sobald möglich – gibt substanzspezifische Therapieempfehlungen. Erstversorgung hat aber Vorrang."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Intoxikation – was wird oft vergessen?",opts:["Die Einsatznummer als Eskalationsmaßnahme bei Therapieversagen","Der Name des Fahrers unter Berücksichtigung des Patientenalters","Bewusst unterlassene Maßnahmen und deren Begründung","Die Transportzeit nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"Intoxikation: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:49,title:"Akutes Lungenödem nachts",bpr:"lungenoedem",scenario:"72-jähriger Mann, bekannte Herzinsuffizienz. Plötzlich schwere Dyspnoe im Liegen, Orthopnoe. Feuchte RG beidseits, SpO₂ 82%, RR 160/100, HF 110.",
steps:[
{q:"Wie lagern Sie den Patienten?",opts:["Oberkörper hoch, Beine tief","Schocklage mit regelmäßiger Verlaufskontrolle","Seitenlage bei Verdacht auf kritische Verschlechterung","Flach unter Beachtung möglicher Wechselwirkungen"],correct:0,explanation:"Oberkörperhochlagerung + Beine tief = Reduktion der Vorlast."},
{q:"Welche Atemunterstützung geben Sie?",opts:["Beutel-Maske-Beatmung","Intubation als leitliniengerechte Notfallmaßnahme","NIV/CPAP (PEEP 5-10 cmH₂O)","Nur Sauerstoff nach klinischer Einschätzung"],correct:2,explanation:"CPAP mit PEEP 5-10 cmH₂O verbessert Oxygenierung und reduziert Vorlast."},
{q:"Medikamentöse Therapie?",opts:["Nur Furosemid gemäß Behandlungspfad","Glyceroltrinitrat sublingual + Furosemid i.v.","Epinephrin + Amiodaron bei stabilen Kreislaufverhältnissen","Salbutamol + Prednisolon unter kontinuierlichem Monitoring"],correct:1,explanation:"Glyceroltrinitrat 0,4 mg sublingual (Vorlastsenkung) + Furosemid 20 mg i.v."},
{q:"Was ist die häufigste Ursache des kardialen Lungenödems?",opts:["Akute Linksherzinsuffizienz","Pneumonie nach ABCDE-Reevaluation","Klappenerkrankung","Lungenembolie bei gesichertem Atemweg"],correct:0,explanation:"Häufigste Ursache: Akute Linksherzinsuffizienz (bei dekompensierter Herzinsuffizienz, ACS, hypertensiver Krise)."},
{q:"Wann ist Glyceroltrinitrat kontraindiziert?",opts:["RRsyst < 100 mmHg, PDE-5-Hemmer (Sildenafil) in letzten 48h","Nur bei Kindern laut aktuellem Algorithmus","Immer bei Lungenödem nach Sicherung der Vitalfunktionen, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Nie unter Beachtung der Kontraindikationen"],correct:0,explanation:"Glyceroltrinitrat KI: RRsyst < 100 mmHg, Einnahme von PDE-5-Hemmern (Viagra etc.) in letzten 24-48h."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Lungenödem – welche Kerninfo?",opts:["Nur den Transportweg bei dokumentierter Indikation","Nur ob der Patient Schmerzen hat mit anschließender Transportentscheidung","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen nach initialer Stabilisierung"],correct:2,explanation:"Lungenödem: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:50,title:"Lungenödem bei Niereninsuffizienz",bpr:"lungenoedem",scenario:"65-jährige Dialysepatientin, Dialyse ausgelassen. Massive Dyspnoe, feuchte RG, beinödeme. SpO₂ 80%, RR 200/120.",
steps:[
{q:"Was ist die Ursache des Lungenödems hier?",opts:["Herzinfarkt gemäß SOP des Rettungsdienstes","Asthma bei fehlenden Kontraindikationen","Volumenüberladung bei ausgelassener Dialyse","Pneumonie unter Berücksichtigung des klinischen Bildes"],correct:2,explanation:"Dialyse ausgelassen → Volumenüberladung → kardialer Rückstau → Lungenödem."},
{q:"Furosemid-Gabe sinnvoll?",opts:["Ja, wie immer mit Voranmeldung in der Zielklinik","Doppelte Dosis nach Ausschluss reversibler Ursachen","Kontraindiziert bei hämodynamischer Instabilität","Eingeschränkt wirksam bei Anurie/schwerer Niereninsuffizienz"],correct:3,explanation:"Bei Anurie/schwerer Niereninsuffizienz: Furosemid eingeschränkt wirksam. CPAP + Nitro primär!"},
{q:"Was ist das dringendste Transportziel?",opts:["Pflegeheim unter Zeitdruck im Einsatzgeschehen","Rehabilitation als initiale Maßnahme vor Transport","Klinik mit Dialysemöglichkeit","Hausarzt bei gesicherter Diagnose und Indikation"],correct:2,explanation:"Dringende Dialyse notwendig → Klinik mit Dialysemöglichkeit!"},
{q:"Was ist besonders bei Dialysepatienten zu beachten?",opts:["Nichts mit begleitender Sauerstofftherapie","Kein Shunt-Arm für i.v.-Zugang, Elektrolytstörungen, Volumenüberladung","Nur Allergie nach differentialdiagnostischer Abwägung","Nur Medikamente im Rahmen der Notfallversorgung unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf"],correct:1,explanation:"Dialysepatient: KEINEN Zugang am Shunt-Arm! Elektrolytstörungen (K⁺!), Volumenüberladung als Ursache."},
{q:"Warum ist CPAP hier besonders effektiv?",opts:["Nur O₂ bei persistierender Symptomatik trotz Erstmaßnahmen","Nur bei COPD nach Anlage eines venösen Zugangs","PEEP reduziert Vorlast + verbessert Oxygenierung bei volumenüberladenen Patienten","Nur Komfort gemäß den Empfehlungen des ÄLRD"],correct:2,explanation:"CPAP/PEEP: Reduziert venösen Rückstrom (Vorlast) + eröffnet kollabierende Alveolen → doppelter Effekt."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Lungenödem – nach welcher Struktur?",opts:["Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach persönlichem Ermessen unter Beachtung der Dosierungsgrenzen, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus","Nach Dringlichkeit der Diagnostik bei fortbestehender klinischer Verschlechterung","Alphabetisch nach Befunden mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Lungenödem: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:51,title:"Flash Lungenödem",bpr:"lungenoedem",scenario:"58-Jährige, plötzlich schwerste Atemnot aus völliger Gesundheit. Schaumiges Sputum, SpO₂ 78%, RR 180/110. Keine kardiale Vorgeschichte.",
steps:[
{q:"Was könnte ein Flash-Lungenödem auslösen?",opts:["Nur Pneumonie nach dokumentierter Erstuntersuchung","Nur Nierenversagen unter Einbeziehung der Patientenanamnese","Nur chronische Herzinsuffizienz bei fehlendem Ansprechen auf Ersttherapie","Akute hypertensive Entgleisung, ACS, Klappeninsuffizienz"],correct:3,explanation:"Flash-Lungenödem: Akute Ursachen wie hypertensive Krise, akuter MI, akute Klappeninsuffizienz."},
{q:"Was ist Ihre erste Priorität?",opts:["Morphin i.v als Eskalationsmaßnahme bei Therapieversagen","CPAP + Sauerstoff + Lagerung","12-Kanal-EKG unter Berücksichtigung des Patientenalters","Furosemid i.v nach Erhebung eines Basis-Monitorings"],correct:1,explanation:"Oxygenierung hat höchste Priorität: CPAP + O₂ + Oberkörperhochlagerung sofort."},
{q:"Morphin beim Lungenödem – wann?",opts:["Nur bei Schmerzen mit regelmäßiger Verlaufskontrolle","Nie bei Verdacht auf kritische Verschlechterung","Immer unter Beachtung möglicher Wechselwirkungen","Zurückhaltend, ggf. bei Angst/Unruhe"],correct:3,explanation:"Morphin beim Lungenödem nur zurückhaltend einsetzen – ggf. bei Angst/Unruhe, Vorsicht Atemdepression."},
{q:"Was unterscheidet Flash-Lungenödem vom chronisch dekompensierten?",opts:["Nur Vorerkrankung als leitliniengerechte Notfallmaßnahme","Nichts nach klinischer Einschätzung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur Alter gemäß Behandlungspfad","Akuter Beginn aus Wohlbefinden, oft hypertensive Krise als Auslöser"],correct:3,explanation:"Flash-Lungenödem: Perakuter Beginn, oft durch hypertensive Krise, akutes ACS oder akute Klappeninsuffizienz."},
{q:"Welche Diagnostik führen Sie durch?",opts:["Nur SpO₂ bei stabilen Kreislaufverhältnissen","Nur EKG unter kontinuierlichem Monitoring","Nur RR nach ABCDE-Reevaluation","12-Kanal-EKG + SpO₂ + RR + Auskultation + BZ"],correct:3,explanation:"12-Kanal-EKG (ACS?), SpO₂, RR, Auskultation (feuchte RG?), BZ → Ursachensuche parallel zur Therapie."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Lungenödem – was wird oft vergessen?",opts:["Die Einsatznummer bei gesichertem Atemweg","Der Name des Fahrers laut aktuellem Algorithmus","Die Transportzeit nach Sicherung der Vitalfunktionen","Bewusst unterlassene Maßnahmen und deren Begründung"],correct:3,explanation:"Lungenödem: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:52,title:"Status epilepticus",bpr:"krampf_erw",scenario:"42-jähriger Mann, bekannte Epilepsie. Generalisierter tonisch-klonischer Krampfanfall seit > 5 Minuten. GCS 3, SpO₂ 87%.",
steps:[
{q:"Wie dosieren Sie Midazolam antikonvulsiv?",opts:["0,01 mg/kgKG titriert unter Beachtung der Kontraindikationen","0,5 mg i.v bei dokumentierter Indikation","0,1 mg/kgKG i.v. – adäquat hoch, NICHT titrieren!","2 mg i.v. langsam mit anschließender Transportentscheidung"],correct:2,explanation:"Antikonvulsiv: 0,1 mg/kgKG – ADÄQUAT HOCH dosieren, NICHT titrieren wie bei Sedierung!"},
{q:"Kein i.v.-Zugang. Alternative?",opts:["Oral nach initialer Stabilisierung","10 mg nasal oder buccal oder i.m.","Abwarten bis Zugang gemäß SOP des Rettungsdienstes","Rectal bei fehlenden Kontraindikationen"],correct:1,explanation:"Erwachsene ohne i.v.-Zugang: 10 mg Midazolam nasal/buccal/i.m. (5 mg pro Nasenloch)."},
{q:"Was muss IMMER ausgeschlossen werden?",opts:["Lungenembolie unter Berücksichtigung des klinischen Bildes","Aortensyndrom mit Voranmeldung in der Zielklinik","Dehydratation nach Ausschluss reversibler Ursachen","Hypoglykämie (BZ messen!)"],correct:3,explanation:"BZ-Messung obligat! Hypoglykämie ist häufige und einfach behandelbare Ursache."},
{q:"Was gilt als Status epilepticus?",opts:["Nur > 30 min bei hämodynamischer Instabilität","Jeder Krampfanfall unter Zeitdruck im Einsatzgeschehen","Krampfanfall > 5 Minuten oder rezidivierende Anfälle ohne Erholung","Nur bei Kindern als initiale Maßnahme vor Transport"],correct:2,explanation:"Status epilepticus: Krampfanfall > 5 min ODER rezidivierende Anfälle ohne zwischenzeitliche Erholung. Lebensbedrohlich!"},
{q:"Welche Midazolam-Dosis für einen 80 kgKG Erwachsenen i.v.?",opts:["20 mg bei gesicherter Diagnose und Indikation","0,8 mg mit begleitender Sauerstofftherapie","2 mg nach differentialdiagnostischer Abwägung","8 mg (0,1 mg/kgKG)"],correct:3,explanation:"Antikonvulsiv: 0,1 mg/kgKG → 80 × 0,1 = 8 mg i.v. ADÄQUAT HOCH, NICHT titrieren!"}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Krampfanfall Erwachsene – welche Kerninfo?",opts:["Nur die Diagnose nennen im Rahmen der Notfallversorgung","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur den Transportweg bei persistierender Symptomatik trotz Erstmaßnahmen","Nur ob der Patient Schmerzen hat nach Anlage eines venösen Zugangs, was jedoch in der aktuellen Situation kontraindiziert wäre"],correct:1,explanation:"Krampfanfall Erwachsene: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:53,title:"Erstmaliger Krampfanfall",bpr:"krampf_erw",scenario:"28-jährige Frau, erstmaliger generalisierter Krampfanfall, Dauer ca. 2 Minuten. Bei Eintreffen: postiktal, schläfrig, desorientiert. BZ 95 mg/dl, SpO₂ 95%.",
steps:[
{q:"Krampfanfall hat sistiert. Geben Sie trotzdem Midazolam?",opts:["Ja, prophylaktisch gemäß den Empfehlungen des ÄLRD","Ja, halbe Dosis unter Beachtung der Dosierungsgrenzen","Nein – sistierter Krampf braucht kein Antikonvulsivum","Ja, rectal bei fortbestehender klinischer Verschlechterung"],correct:2,explanation:"Sistierter Krampf: Kein Antikonvulsivum notwendig. Überwachung, Schutz, postiktale Betreuung."},
{q:"Was gehört zur postiktalen Betreuung?",opts:["Schutz, stabile Seitenlage, Beruhigung, BZ-Messung, O₂ bei Bedarf","Midazolam prophylaktisch mit paralleler Vorbereitung des Transports","Sofort entlassen nach dokumentierter Erstuntersuchung","Sofort mobilisieren unter Einbeziehung der Patientenanamnese"],correct:0,explanation:"Postiktal: Schutz vor Verletzung, Seitenlage, O₂ bei Bedarf, BZ-Kontrolle, ruhige Ansprache."},
{q:"Transport indiziert?",opts:["Nein, wenn bewusstseinsklar bei fehlendem Ansprechen auf Ersttherapie","Ja, erstmaliger Krampfanfall muss klinisch abgeklärt werden","Nur bei Status epilepticus als Eskalationsmaßnahme bei Therapieversagen","Nur bei Kindern unter Berücksichtigung des Patientenalters"],correct:1,explanation:"Erstmaliger Krampfanfall: IMMER klinische Abklärung (Bildgebung, EEG, Labor)."},
{q:"Welche Verletzungen prüfen Sie postiktal?",opts:["Keine nach Erhebung eines Basis-Monitorings","Nur Zunge mit regelmäßiger Verlaufskontrolle","Zungenbiss, Schulterluxation, Frakturen, Kopfverletzungen","Nur Kopf bei Verdacht auf kritische Verschlechterung"],correct:2,explanation:"Typische Verletzungen: Lateraler Zungenbiss, Schulterluxation, WK-Frakturen, Kopfplatzwunden. Systematisch prüfen!"},
{q:"Darf die Patientin bei erstmaligem Krampfanfall Auto fahren?",opts:["Ja unter Beachtung möglicher Wechselwirkungen","Nein – Fahrverbot bis neurologische Abklärung und anfallsfreies Intervall","Nur kurze Strecken als leitliniengerechte Notfallmaßnahme","Sofort wieder nach klinischer Einschätzung"],correct:1,explanation:"Erstmaliger Krampfanfall → Fahruntauglichkeit bis neurologische Abklärung + anfallsfreies Intervall (je nach Ursache 3-12 Monate)."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Krampfanfall Erwachsene – nach welcher Struktur?",opts:["Nach persönlichem Ermessen gemäß Behandlungspfad","Nach Dringlichkeit der Diagnostik bei stabilen Kreislaufverhältnissen","Alphabetisch nach Befunden unter kontinuierlichem Monitoring und anschließende Reevaluation nach spätestens 5 Minuten","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern"],correct:3,explanation:"Krampfanfall Erwachsene: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:54,title:"Krampfanfall bei Alkoholentzug",bpr:"krampf_erw",scenario:"50-jähriger Mann, bekannter Alkoholismus. Generalisierter Krampfanfall in der Notaufnahme-Wartezone. GCS 6, Tremor, schweißig.",
steps:[
{q:"Woran denken Sie neben Alkoholentzug?",opts:["Nur Fieberkrampf nach ABCDE-Reevaluation","Nur Epilepsie bei gesichertem Atemweg","Nur Entzug laut aktuellem Algorithmus","Hypoglykämie, Intoxikation, Elektrolytstörungen, intrakranielle Pathologie"],correct:3,explanation:"DD bei Alkoholikern: Hypoglykämie (häufig!), Intoxikation, Elektrolytstörungen, Schädel-Hirn-Trauma, intrakranielle Blutung."},
{q:"Midazolam-Gabe. Besonderheit bei Alkoholikern?",opts:["Immer Phenobarbital nach Sicherung der Vitalfunktionen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Halbe Dosis unter Beachtung der Kontraindikationen","Ggf. erhöhter Bedarf durch Kreuztoleranz Alkohol/Benzodiazepine","Nie Benzodiazepine bei dokumentierter Indikation"],correct:2,explanation:"Alkoholiker können eine Kreuztoleranz zu Benzodiazepinen haben → ggf. höherer Bedarf."},
{q:"BZ 42 mg/dl. Was tun Sie?",opts:["Insulingabe mit anschließender Transportentscheidung","Glucose i.v. – Hypoglykämie behandeln!","Abwarten nach initialer Stabilisierung","Glucagon i.m gemäß SOP des Rettungsdienstes"],correct:1,explanation:"BZ 42 mg/dl = Hypoglykämie! Glucose i.v. ist essenziell – kann allein den Krampf beenden."},
{q:"Welche zusätzliche Gefahr besteht bei Alkoholikern?",opts:["Aspirationsgefahr (Erbrechen), SHT (Sturzneigung), Wernicke-Enzephalopathie","Nur Dehydratation bei fehlenden Kontraindikationen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Keine unter Berücksichtigung des klinischen Bildes","Nur Tremor mit Voranmeldung in der Zielklinik"],correct:0,explanation:"Alkoholiker: Erhöhte Aspirationsgefahr, Sturzneigung → SHT, Wernicke-Enzephalopathie (Thiaminmangel)."},
{q:"Was tun Sie nach Krampfdurchbrechung und BZ-Korrektur?",opts:["Nur beobachten nach Ausschluss reversibler Ursachen","Transport in Klinik – multiple DD abklären (SHT, Blutung, Elektrolyte)","Hausarzt bei hämodynamischer Instabilität","Entlassen unter Zeitdruck im Einsatzgeschehen"],correct:1,explanation:"Kliniktransport obligat: DD SHT, intrakranielle Blutung, Elektrolytstörungen, Infektion, Entzugsdelir."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Krampfanfall Erwachsene – was wird oft vergessen?",opts:["Der Name des Fahrers als initiale Maßnahme vor Transport","Bewusst unterlassene Maßnahmen und deren Begründung","Die Einsatznummer bei gesicherter Diagnose und Indikation","Die Transportzeit mit begleitender Sauerstofftherapie"],correct:1,explanation:"Krampfanfall Erwachsene: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:55,title:"Fieberkrampf Kleinkind",bpr:"krampf_kind",scenario:"2-jähriges Kind, Fieber 39,8°C. Plötzlich generalisierter tonisch-klonischer Krampfanfall seit 2 Minuten. Eltern in Panik.",
steps:[
{q:"Häufigste Krampfursache bei Kleinkindern?",opts:["Hypoglykämie","Epilepsie","Fieberkrampf","Intoxikation"],correct:2,explanation:"Fieberkrampf ist die häufigste Ursache von Krampfanfällen im Kindesalter (6 Monate – 5 Jahre)."},
{q:"Welche Midazolam-Dosis buccal bei einem 2-Jährigen?",opts:["7,5 mg","10 mg","2,5 mg","5 mg"],correct:3,explanation:"Buccal: 1-4 Jahre = 5 mg Midazolam (Buccolam® 1 ml)."},
{q:"Krampf sistiert nach 3 Minuten spontan. Was nun?",opts:["Nichts weiter nach differentialdiagnostischer Abwägung","Fiebersenkung: physikalische Kühlung + Paracetamol/Ibuprofen","Sofort intubieren im Rahmen der Notfallversorgung","Trotzdem Midazolam geben bei persistierender Symptomatik trotz Erstmaßnahmen"],correct:1,explanation:"Nach sistiertem Fieberkrampf: Fiebersenkung! Physikalische Kühlung + Paracetamol oder Ibuprofen."},
{q:"Was ist ein komplizierter Fieberkrampf?",opts:["Dauer > 15 min, fokal, rezidivierend innerhalb 24h, postiktales Defizit","Jeder Fieberkrampf nach Anlage eines venösen Zugangs","Nur bei Fieber > 40°C gemäß den Empfehlungen des ÄLRD","Nur bei Säuglingen unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Komplizierter FK: > 15 min, fokal (nicht generalisiert), rezidivierend innerhalb 24h, postiktales neurologisches Defizit."},
{q:"Welche Fiebersenkung ist beim Kleinkind nach Fieberkrampf geeignet (SAA)?",opts:["Nur physikalische Kühlung bei fortbestehender klinischer Verschlechterung","ASS mit paralleler Vorbereitung des Transports","Paracetamol rektal (gewichtsadaptiert) oder Ibuprofen oral (gewichtsadaptiert)","Metamizol i.v nach dokumentierter Erstuntersuchung"],correct:2,explanation:"SAA: Paracetamol rektal (125/250/500 mg je Gewicht) oder Ibuprofen oral als Suspension (50-200 mg je Gewicht). KEIN ASS bei Kindern <18 J.!"}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Krampfanfall Kind – welche Kerninfo?",opts:["Nur den Transportweg unter Einbeziehung der Patientenanamnese","Nur ob der Patient Schmerzen hat bei fehlendem Ansprechen auf Ersttherapie","Nur die Diagnose nennen als Eskalationsmaßnahme bei Therapieversagen","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit"],correct:3,explanation:"Krampfanfall Kind: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:56,title:"Prolongierter kindlicher Krampfanfall",bpr:"krampf_kind",scenario:"7-jähriges Kind, bekannte Epilepsie. Krampfanfall seit > 5 min. GCS 3. SpO₂ 88%.",
steps:[
{q:"Midazolam buccal für 7-Jähriges?",opts:["7,5 mg","10 mg","2,5 mg","5 mg"],correct:0,explanation:"Buccal: 5-9 Jahre = 7,5 mg Midazolam. Einmalige Repetition möglich."},
{q:"Alternative nasal per MAD für ein 25 kg Kind?",opts:["2,5 mg","10 mg","15 mg","5 mg"],correct:1,explanation:"Nasal per MAD: > 20 kgKG = 10 mg Midazolam."},
{q:"Krampf sistiert. BZ 48 mg/dl. Therapie?",opts:["Glucagon i.m unter Berücksichtigung des Patientenalters","Orale Glucose nach Erhebung eines Basis-Monitorings","Glucose i.v.: 0,2 g/kgKG = 5 g","Insulin mit regelmäßiger Verlaufskontrolle"],correct:2,explanation:"Kind 25 kgKG: 0,2 g/kgKG = 5 g Glucose i.v. BZ-Kontrolle nach 5 min."},
{q:"Was ist der Unterschied zwischen buccaler und nasaler Gabe?",opts:["Nasal nur für Erwachsene bei Verdacht auf kritische Verschlechterung","Buccal = nasal unter Beachtung möglicher Wechselwirkungen","Buccal: in Wangentasche. Nasal: per MAD in Nasenlöcher (je 50%)","Kein Unterschied als leitliniengerechte Notfallmaßnahme"],correct:2,explanation:"Buccal: Midazolam in Wangentasche applizieren. Nasal: Per MAD (Mucosal Atomization Device), 50% pro Nasenloch."},
{q:"Wann repetieren Sie Midazolam?",opts:["Nie nach klinischer Einschätzung","Alle 2 min gemäß Behandlungspfad","5 mal bei stabilen Kreislaufverhältnissen","Einmalige Repetition nach 10 min bei anhaltendem Krampf"],correct:3,explanation:"Einmalige Repetition nach 10 Minuten bei anhaltendem Krampfanfall. Danach: NA-Nachforderung für Eskalation."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Krampfanfall Kind – nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik unter kontinuierlichem Monitoring","Nach persönlichem Ermessen nach ABCDE-Reevaluation","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Alphabetisch nach Befunden bei gesichertem Atemweg"],correct:2,explanation:"Krampfanfall Kind: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:57,title:"Neugeborenen-Krampfanfall",bpr:"krampf_kind",scenario:"Neugeborenes, 5 Tage alt. Subtile rhythmische Bewegungen, Apnoe-Episoden. Eltern bemerken 'merkwürdiges Zucken'.",
steps:[
{q:"Ist Midazolam bei Neugeborenen erlaubt?",opts:["Ja, immer laut aktuellem Algorithmus","Ab Geburt erlaubt nach Sicherung der Vitalfunktionen","Nur rectal unter Beachtung der Kontraindikationen","Keine Anwendung < 3 Monate laut SAA"],correct:3,explanation:"SAA Midazolam: Keine Anwendung bei Pat. < 3 Monate. NA-Nachforderung!"},
{q:"Was ist die wichtigste Erstmaßnahme?",opts:["Intubation bei dokumentierter Indikation","Phenobarbital mit anschließender Transportentscheidung","Midazolam buccal nach initialer Stabilisierung","Basismaßnahmen, O₂, BZ-Messung, Temperatur"],correct:3,explanation:"Basismaßnahmen: Sauerstoff, BZ-Kontrolle, Temperatur. Medikamentöse Therapie durch NA."},
{q:"Welcher Transportmodus?",opts:["Sofortiger Transport mit NA → Kinderklinik","Ambulant gemäß SOP des Rettungsdienstes","Nächster RTW bei fehlenden Kontraindikationen","Hubschrauber immer unter Berücksichtigung des klinischen Bildes"],correct:0,explanation:"Neugeborener Krampfanfall ist ein Notfall → NA-Nachforderung + Transport Kinderklinik."},
{q:"Was unterscheidet neonatale Krämpfe von Krämpfen bei Älteren?",opts:["Immer generalisiert mit Voranmeldung in der Zielklinik","Oft subtil: Augenbewegungen, Schmatzen, Apnoe, 'Radfahrbewegungen'","Nur Fieberkrämpfe nach Ausschluss reversibler Ursachen","Nichts bei hämodynamischer Instabilität"],correct:1,explanation:"Neonatale Krämpfe: Oft subtil und schwer zu erkennen. Augenzucken, Schmatzen, Apnoe, tonische Streckung, Radfahrbewegungen."},
{q:"Warum ist die Prognose bei neonatalen Krämpfen ernst?",opts:["Nur bei Frühgeborenen unter Zeitdruck im Einsatzgeschehen, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Nur temporär als initiale Maßnahme vor Transport","Oft Zeichen einer schweren Grunderkrankung (Asphyxie, Hirnblutung, Infektion, Stoffwechsel)","Immer harmlos bei gesicherter Diagnose und Indikation"],correct:2,explanation:"Neonatale Krämpfe: Ursachen oft schwerwiegend (Asphyxie, intrakranielle Blutung, Meningitis, Stoffwechselstörung). Rasche Abklärung!"}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Krampfanfall Kind – was wird oft vergessen?",opts:["Der Name des Fahrers mit begleitender Sauerstofftherapie","Bewusst unterlassene Maßnahmen und deren Begründung","Die Transportzeit nach differentialdiagnostischer Abwägung","Die Einsatznummer im Rahmen der Notfallversorgung"],correct:1,explanation:"Krampfanfall Kind: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:58,title:"Massive Lungenembolie",bpr:"lae",scenario:"55-jährige Frau, Z.n. Knie-TEP vor 10 Tagen. Plötzliche Dyspnoe, Brustschmerz, Synkope. RR 85/55, HF 125, SpO₂ 84%.",
steps:[
{q:"Welche Risikofaktoren sind erkennbar?",opts:["Asthma bei persistierender Symptomatik trotz Erstmaßnahmen","Rauchen nach Anlage eines venösen Zugangs","Kürzliche OP + Immobilisation → LAE-Risiko","Nur Alter gemäß den Empfehlungen des ÄLRD unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf"],correct:2,explanation:"Frische OP + Immobilisation sind Hauptrisikofaktoren für tiefe Venenthrombose → Lungenembolie."},
{q:"Wells-Score ≥5 und sPESI ≥1. Was geben Sie?",opts:["ASS unter Beachtung der Dosierungsgrenzen","Amiodaron bei fortbestehender klinischer Verschlechterung","Heparin 5.000 I.E. i.v.","Furosemid mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Wells ≥5 + sPESI ≥1 → Heparin 5.000 I.E. i.v. Hochdosierte O₂-Gabe."},
{q:"Welche Atemunterstützung?",opts:["Keine nach dokumentierter Erstuntersuchung","Nur Nasensonde unter Einbeziehung der Patientenanamnese","Hochdosierte O₂-Gabe, erwäge NIV","Intubation bei fehlendem Ansprechen auf Ersttherapie"],correct:2,explanation:"Hochdosierte O₂-Gabe, NIV erwägen. Bei Schock: Volumentherapie vorsichtig."},
{q:"Was ist der Wells-Score?",opts:["Nur für Schlaganfall als Eskalationsmaßnahme bei Therapieversagen","Klinische Wahrscheinlichkeit für LAE (Punkte für Risikofaktoren)","Nur für ACS unter Berücksichtigung des Patientenalters, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus","Schmerzskala nach Erhebung eines Basis-Monitorings"],correct:1,explanation:"Wells-Score: Klinisches Scoring für LAE-Wahrscheinlichkeit. Berücksichtigt: TVT-Zeichen, HF, Immobilisation, Hämoptysen, Malignom etc."},
{q:"Welche Volumentherapie bei LAE mit Schock?",opts:["Keine mit regelmäßiger Verlaufskontrolle","Aggressiv 2 Liter bei Verdacht auf kritische Verschlechterung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Zurückhaltende, bedarfsgerechte Volumengabe (Rechtsherzbelastung!)","Furosemid stattdessen unter Beachtung möglicher Wechselwirkungen"],correct:2,explanation:"BPR LAE: Bedarfsgerechte Volumengabe mit VEL. Zurückhaltend! Rechtsherz ist bereits überlastet → zu viel Volumen verschlechtert die Situation."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei V.a. LAE – welche Befunde sind entscheidend?",opts:["Nur der SpO₂-Wert als leitliniengerechte Notfallmaßnahme","Nur ob Thoraxschmerz besteht nach klinischer Einschätzung","B: Dyspnoe + SpO₂ + C: Tachykardie, Hypotonie, Halsvenenstauung + Wells-Score-Ergebnis","Nur der Wells-Score gemäß Behandlungspfad, was jedoch in der aktuellen Situation kontraindiziert wäre"],correct:2,explanation:"LAE-Priorität: B (Dyspnoe, SpO₂, Tachypnoe) + C (Tachykardie, RR, Schockzeichen, Halsvenenstauung). Wells-Score-Ergebnis bei N integrieren."}]},
{id:59,title:"LAE in der Schwangerschaft",bpr:"lae",scenario:"30-jährige Schwangere (34. SSW). Plötzliche Atemnot, Brustschmerz, geschwollenes linkes Bein. HF 110, RR 100/70, SpO₂ 91%.",
steps:[
{q:"Welcher besondere Risikofaktor liegt vor?",opts:["Kein besonderer bei stabilen Kreislaufverhältnissen und anschließende Reevaluation nach spätestens 5 Minuten","Alter unter kontinuierlichem Monitoring","Schwangerschaft (Hyperkoagulabilität) + Zeichen tiefer Venenthrombose","Geschlecht nach ABCDE-Reevaluation"],correct:2,explanation:"Schwangerschaft = Hyperkoagulabilität + Stase → erhöhtes LAE-Risiko. Geschwollenes Bein = TVT-Zeichen."},
{q:"Darf Heparin in der Schwangerschaft gegeben werden?",opts:["Nur niedermolekulares Heparin bei gesichertem Atemweg","Nie in der Schwangerschaft laut aktuellem Algorithmus","Nein, kontraindiziert nach Sicherung der Vitalfunktionen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Ja, Heparin ist plazentagängig aber bei vitaler Indikation erlaubt"],correct:3,explanation:"Heparin bei vitaler Indikation in der Schwangerschaft möglich (Nutzen > Risiko)."},
{q:"Wie lagern Sie die Schwangere?",opts:["Kopftieflage unter Beachtung der Kontraindikationen mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Flach auf dem Rücken bei dokumentierter Indikation","Linksseitenlage (V.-cava-Kompressionssyndrom vermeiden)","Oberkörper hoch mit anschließender Transportentscheidung"],correct:2,explanation:"Schwangere ab 20. SSW: Linksseitenlage zur Vermeidung des V.-cava-Kompressionssyndroms."},
{q:"Welche Besonderheit beachten Sie bei der Reanimation Schwangerer?",opts:["Nur Rückenlage nach initialer Stabilisierung","Keine CPR in Schwangerschaft gemäß SOP des Rettungsdienstes, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Nichts bei fehlenden Kontraindikationen","Manuelle Uterusverlagerung nach links oder 15° Linksseitenlage"],correct:3,explanation:"Schwangere: Manuelle Uterusverlagerung nach links oder 15° Linksseitenlage → V.-cava-Kompressionssyndrom vermeiden."},
{q:"Wie behandeln Sie die begleitende TVT?",opts:["Kompression unter Berücksichtigung des klinischen Bildes","Tieflagerung + Immobilisation, Heparin i.v.","Hochlagerung mit Voranmeldung in der Zielklinik","Massage nach Ausschluss reversibler Ursachen"],correct:1,explanation:"TVT: Tieflagerung, Immobilisation, Heparin i.v. (bei vitaler Indikation auch in Schwangerschaft). Transport Klinik."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei LAE – was ist für die Klinik am wichtigsten?",opts:["Nur die Lagerung bei hämodynamischer Instabilität","Heparin 5.000 IE gegeben? (Uhrzeit!), O₂-Therapie, Volumen, ggf. Lyse-Entscheidung bei instabiler LAE","Nur ob ein EKG geschrieben wurde unter Zeitdruck im Einsatzgeschehen","Nur der Transport als initiale Maßnahme vor Transport"],correct:1,explanation:"LAE-Handlungen: Heparin (Dosis+Uhrzeit), O₂-Therapie, Volumen, Katecholamine bei Schock, bei instabiler LAE: Lyse-Entscheidung + Alteplase-Gabe."}]},
{id:60,title:"LAE mit Kreislaufstillstand",bpr:"lae",scenario:"48-jähriger Mann, bekannte tiefe Beinvenenthrombose. Plötzlicher Kreislaufstillstand. PEA im Monitor.",
steps:[
{q:"Was ist die wahrscheinlichste Ursache der PEA?",opts:["ACS bei gesicherter Diagnose und Indikation","Massive Lungenembolie (HITS: Thrombose)","Spannungspneumothorax mit begleitender Sauerstofftherapie","Hyperkaliämie nach differentialdiagnostischer Abwägung"],correct:1,explanation:"Bekannte TVT + plötzlicher Kreislaufstillstand → massive Lungenembolie als Ursache (HITS)."},
{q:"Wie gehen Sie vor?",opts:["Nur Standard-CPR im Rahmen der Notfallversorgung","Thoraxentlastungspunktion","Nur Heparin bei persistierender Symptomatik trotz Erstmaßnahmen","CPR + Lyse durch NA erwägen"],correct:3,explanation:"Bei V.a. massive LAE als Ursache des Kreislaufstillstands: Systemische Lyse durch NA erwägen."},
{q:"Besonderheit der CPR-Dauer bei V.a. LAE?",opts:["Verlängerte CPR sinnvoll (>60 min bei Lyse)","Maximal 20 min nach Anlage eines venösen Zugangs","Wie immer gemäß den Empfehlungen des ÄLRD","Schnell abbrechen unter Beachtung der Dosierungsgrenzen"],correct:0,explanation:"Nach Lysetherapie: CPR mindestens 60-90 min fortführen – Lyse braucht Zeit zu wirken."},
{q:"Was bedeutet HITS?",opts:["Schläge bei fortbestehender klinischer Verschlechterung","Nur Herz mit paralleler Vorbereitung des Transports","Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneu","Nur Trauma nach dokumentierter Erstuntersuchung unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf"],correct:2,explanation:"HITS = reversible Ursachen: Herzbeuteltamponade, Intoxikation, Thrombose (LAE/ACS), Spannungspneumothorax."},
{q:"Wie lange reanimieren Sie nach Lyse?",opts:["Mindestens 60-90 min","5 min unter Einbeziehung der Patientenanamnese","10 min bei fehlendem Ansprechen auf Ersttherapie","20 min als Eskalationsmaßnahme bei Therapieversagen"],correct:0,explanation:"Nach Lysetherapie: CPR mindestens 60-90 min fortführen. Lyse braucht Zeit zu wirken!"}
,
{q:"Übergabe (SINNHAFT): Anamnese (A) bei V.a. LAE – welche Risikofaktoren gehören dazu?",opts:["Nur die Dauermedikation unter Berücksichtigung des Patientenalters","Nur die Familienanamnese nach Erhebung eines Basis-Monitorings","Immobilisation, kürzliche OP, Tumorerkrankung, orale Kontrazeption, Thrombose-Anamnese","Nur die Blutgruppe mit regelmäßiger Verlaufskontrolle"],correct:2,explanation:"LAE-Risikofaktoren (Anamnese): Immobilisation, OP <4 Wochen, Malignom, orale Kontrazeption, Z.n. TVT/LAE, Schwangerschaft, lange Flugreise."}]},
{id:61,title:"Pseudokrupp-Anfall nachts",bpr:"obstruktion_kind",scenario:"3-jähriges Kind, bellender Husten, inspiratorischer Stridor in Ruhe, heisere Stimme. Kein Fieber. Eltern berichten: Beginn plötzlich um 2 Uhr nachts.",
steps:[
{q:"Was ist die wahrscheinlichste Diagnose?",opts:["Fremdkörperaspiration bei Verdacht auf kritische Verschlechterung","Pseudokrupp (Laryngotracheobronchitis)","Epiglottitis unter Beachtung möglicher Wechselwirkungen","Asthma als leitliniengerechte Notfallmaßnahme"],correct:1,explanation:"Bellender Husten + Stridor + heisere Stimme + nachts + Kleinkind = typischer Pseudokrupp."},
{q:"Erste medikamentöse Maßnahme?",opts:["Prednisolon rektal + Epinephrin-Vernebelung","Salbutamol nach klinischer Einschätzung","Antibiotikum gemäß Behandlungspfad","Midazolam bei stabilen Kreislaufverhältnissen"],correct:0,explanation:"Pseudokrupp: Prednisolon rektal (Supp.) + Epinephrin-Vernebelung (4 mg)."},
{q:"Keine Besserung nach Ersttherapie. Was tun Sie?",opts:["Abwarten unter kontinuierlichem Monitoring","Repetition Epinephrin-Vernebelung","Heimlich-Manöver nach ABCDE-Reevaluation","Intubation bei gesichertem Atemweg"],correct:1,explanation:"Bei fehlender Besserung: Repetition der Epinephrin-Vernebelung."},
{q:"Welche Epinephrin-Dosis vernebeln Sie beim Pseudokrupp?",opts:["0,1 mg laut aktuellem Algorithmus","10 mg nach Sicherung der Vitalfunktionen","4 mg (Amp. 1:1000 = 1 mg/ml → 4 ml)","0,5 mg unter Beachtung der Kontraindikationen"],correct:2,explanation:"Epinephrin-Vernebelung beim Pseudokrupp: 4 mg (= 4 ml der 1:1000 Lösung). Lokal abschwellende Wirkung."},
{q:"Wie wichtig ist Beruhigung des Kindes?",opts:["Nur für Eltern bei dokumentierter Indikation","Sehr wichtig – Stress/Weinen verschlimmert den Stridor erheblich","Mäßig wichtig mit anschließender Transportentscheidung","Unwichtig nach initialer Stabilisierung"],correct:1,explanation:"Beruhigung ist therapeutisch! Weinen/Stress → verstärkter Stridor → Teufelskreis. Kind bei Bezugsperson lassen, nicht unnötig manipulieren."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Obstruktion Kind (Krupp/Epiglottitis) – welche Kerninfo?",opts:["Nur den Transportweg gemäß SOP des Rettungsdienstes","Nur ob der Patient Schmerzen hat bei fehlenden Kontraindikationen","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen unter Berücksichtigung des klinischen Bildes"],correct:2,explanation:"Obstruktion Kind (Krupp/Epiglottitis): Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:62,title:"Epiglottitis beim Kleinkind",bpr:"obstruktion_kind",scenario:"4-jähriges Kind, hohes Fieber 40°C, inspiratorischer Stridor, Speichelfluss, sitzt aufrecht. Schnelle Verschlechterung. SpO₂ 88%.",
steps:[
{q:"Warum unterscheidet sich dieses Bild vom Pseudokrupp?",opts:["Hohes Fieber + Speichelfluss + kein bellender Husten → V.a. Epiglottitis","Kein Unterschied mit Voranmeldung in der Zielklinik","Nur Altersunterschied nach Ausschluss reversibler Ursachen","Gleich bei hämodynamischer Instabilität"],correct:0,explanation:"Epiglottitis: Hohes Fieber, kloßige Stimme, Speichelfluss, aufrechtes Sitzen, KEIN bellender Husten."},
{q:"Was dürfen Sie bei V.a. Epiglottitis NICHT tun?",opts:["Beobachten unter Zeitdruck im Einsatzgeschehen, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus","Beruhigen als initiale Maßnahme vor Transport","Sauerstoff geben bei gesicherter Diagnose und Indikation","In den Mund schauen/Racheninspektion (Manipulation kann Totalverschluss auslösen)"],correct:3,explanation:"KEINE Racheninspektion! Manipulation kann Schwellung verschlimmern → kompletter Atemwegsverschluss."},
{q:"Wie ist das Transportkonzept?",opts:["Ambulant mit begleitender Sauerstofftherapie","Nächster Kinderarzt nach differentialdiagnostischer Abwägung, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Sofortiger Transport in Klinik mit Kinderanästhesie – Intubationsbereitschaft!","Langsam und mit Monitoring im Rahmen der Notfallversorgung"],correct:2,explanation:"Notfall! Klinik mit Möglichkeit der Atemwegssicherung unter kontrollierten Bedingungen (Kinderanästhesie)."},
{q:"Welche Impfung schützt gegen die häufigsten Epiglottitis-Erreger?",opts:["Hib-Impfung (Haemophilus influenzae Typ b)","MMR bei persistierender Symptomatik trotz Erstmaßnahmen","Pneumokokken nach Anlage eines venösen Zugangs","Keine gemäß den Empfehlungen des ÄLRD"],correct:0,explanation:"Hib-Impfung hat die Epiglottitis-Inzidenz drastisch gesenkt. Ungeimpfte Kinder sind besonders gefährdet."},
{q:"Was bereiten Sie für den schlimmsten Fall vor?",opts:["Nur Medikamente unter Beachtung der Dosierungsgrenzen","Nichts bei fortbestehender klinischer Verschlechterung","Notfall-Koniotomie-/Intubationsset + EGA bereithalten","Nur Sauerstoff mit paralleler Vorbereitung des Transports"],correct:2,explanation:"Notfall-Atemwegssicherung vorbereiten (EGA, Intubation, Koniotomie-Set). Bei komplettem Atemwegsverschluss → sofortiges Handeln!"}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Obstruktion Kind (Krupp/Epiglottitis) – nach welcher Struktur?",opts:["Nach Dringlichkeit der Diagnostik nach dokumentierter Erstuntersuchung","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach persönlichem Ermessen unter Einbeziehung der Patientenanamnese","Alphabetisch nach Befunden bei fehlendem Ansprechen auf Ersttherapie"],correct:1,explanation:"Obstruktion Kind (Krupp/Epiglottitis): Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:63,title:"Krupp bei Säugling",bpr:"obstruktion_kind",scenario:"10 Monate alter Säugling, bellender Husten, inspiratorischer Stridor bei Aufregung, leichte Einziehungen. Kein Fieber. SpO₂ 93%.",
steps:[
{q:"Erste Maßnahme?",opts:["Intubation als Eskalationsmaßnahme bei Therapieversagen","Antibiotikum unter Berücksichtigung des Patientenalters","Salbutamol nach Erhebung eines Basis-Monitorings","Beruhigung + Sauerstoff + Prednisolon rektal"],correct:3,explanation:"Ruhe bewahren! Stress vermeidet Verschlimmerung. O₂ bedarfsgerecht + Prednisolon rektal."},
{q:"Wann vernebeln Sie Epinephrin?",opts:["Nur durch NA mit regelmäßiger Verlaufskontrolle","Sofort bei jedem Krupp bei Verdacht auf kritische Verschlechterung","Bei Stridor in Ruhe, zunehmender Dyspnoe, schlechter SpO₂","Nie bei Säuglingen unter Beachtung möglicher Wechselwirkungen"],correct:2,explanation:"Epinephrin-Vernebelung bei Stridor in Ruhe, zunehmender Atemarbeit, fallender SpO₂."},
{q:"Transport-Entscheidung?",opts:["Immer ambulant als leitliniengerechte Notfallmaßnahme","Nur bei Fieber nach klinischer Einschätzung","Klinik-Transport – Säuglinge mit Krupp müssen immer überwacht werden","Nur bei SpO₂ < 80% gemäß Behandlungspfad"],correct:2,explanation:"Säuglinge mit Krupp: Immer Kliniktransport – rasche Verschlechterung möglich."},
{q:"Prednisolon-Dosis beim Säugling mit Krupp?",opts:["Nicht indiziert bei stabilen Kreislaufverhältnissen","100 mg Supp. rektal (Rectodelt®)","500 mg unter kontinuierlichem Monitoring","10 mg nach ABCDE-Reevaluation"],correct:1,explanation:"Prednisolon 100 mg Supp. rektal beim Säugling/Kleinkind. Wirkt antientzündlich und abschwellend (Stunden)."},
{q:"Warum ist Pseudokrupp nachts schlimmer?",opts:["Nur Lagerung bei gesichertem Atemweg","Cortisol-Tagesrhythmik (niedrigster Spiegel nachts) + kühle Nachtluft","Zufall laut aktuellem Algorithmus","Nur Angst nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Cortisol (körpereigenes Entzündungshemmer) ist nachts am niedrigsten + kühle, trockene Luft → Schleimhautschwellung verstärkt."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Obstruktion Kind (Krupp/Epiglottitis) – was wird oft vergessen?",opts:["Bewusst unterlassene Maßnahmen und deren Begründung","Der Name des Fahrers unter Beachtung der Kontraindikationen","Die Einsatznummer bei dokumentierter Indikation","Die Transportzeit mit anschließender Transportentscheidung"],correct:0,explanation:"Obstruktion Kind (Krupp/Epiglottitis): Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:64,title:"Motorradunfall mit Polytrauma",bpr:"polytrauma",scenario:"25-jähriger Motorradfahrer, Hochrasanztrauma. Instabiler Thorax rechts, offene Femurfraktur links mit starker Blutung, GCS 10, RR 80/50, HF 135.",
steps:[
{q:"Was ist das erste 'c' im <c>ABCDE?",opts:["Critical bleeding – kritische Blutung stillen","Consciousness nach initialer Stabilisierung","Circulation gemäß SOP des Rettungsdienstes","CPAP bei fehlenden Kontraindikationen"],correct:0,explanation:"<c> = Critical bleeding: Lebensbedrohliche Blutung sofort stillen (Tourniquet, Hämostyptikum)."},
{q:"Offene Femurfraktur mit Blutung. Maßnahme?",opts:["Tourniquet proximal + Immobilisation","Abwarten unter Berücksichtigung des klinischen Bildes","Druckverband genügt mit Voranmeldung in der Zielklinik","Schienung und Hochlagerung"],correct:0,explanation:"Kritische Extremitätenblutung → Tourniquet! Uhrzeit dokumentieren. Plus Immobilisation."},
{q:"Instabiler Thorax. SpO₂ sinkt auf 80%. Woran denken Sie?",opts:["Anaphylaxie nach Ausschluss reversibler Ursachen","Lungenödem bei hämodynamischer Instabilität, was jedoch in der aktuellen Situation kontraindiziert wäre","Asthma unter Zeitdruck im Einsatzgeschehen","Spannungspneumothorax → SAA Thoraxentlastungspunktion"],correct:3,explanation:"Instabiler Thorax + zunehmende Hypoxie + Trauma → V.a. Spannungspneumothorax → Entlastungspunktion!"},
{q:"Welches Medikament bei traumatischer Blutung?",opts:["Amiodaron","Atropin als initiale Maßnahme vor Transport","Prednisolon","Tranexamsäure"],correct:3,explanation:"Tranexamsäure bei traumatischer Blutung so früh wie möglich geben (Antifibrinolytikum)."},
{q:"Was ist die 'permissive Hypotonie'?",opts:["Niedrigen RR bei nicht stillbaren inneren Blutungen tolerieren","Nur bei Kindern bei gesicherter Diagnose und Indikation","RR so hoch wie möglich mit begleitender Sauerstofftherapie und anschließende Reevaluation nach spätestens 5 Minuten","RR ignorieren nach differentialdiagnostischer Abwägung"],correct:0,explanation:"BPR: Permissive Hypotonie bei nicht zugänglichen (inneren) Blutungen akzeptabel. Höherer RR → stärkere Blutung. Cave: NICHT bei SHT!"}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) beim Polytrauma – welche WIE-Info ist entscheidend?",opts:["Unfallmechanismus: Geschwindigkeit, Gurtstatus, Deformation, Einklemmung, Sturzhöhe","Welche Musik im Radio lief im Rahmen der Notfallversorgung, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Ob es geregnet hat bei persistierender Symptomatik trotz Erstmaßnahmen","Welcher Wochentag es ist nach Anlage eines venösen Zugangs"],correct:0,explanation:"Unfallmechanismus bestimmt das Verletzungsmuster! Geschwindigkeit, Gurt, Airbag, Deformation, Einklemmung, Sturzhöhe → Rückschluss auf Verletzungsschwere."}]},
{id:65,title:"Kindliches Polytrauma nach Fenstersturz",bpr:"polytrauma",scenario:"4-jähriges Kind, Sturz aus dem 3. Stock. Bewusstlos (GCS 6), instabiles Becken, abdominelle Prellmarken, Schürfungen am Kopf.",
steps:[
{q:"Erstversorgung nach <c>ABCDE. Welcher Zugang?",opts:["i.v. oder i.o. bei fehlgeschlagenem i.v.","Nur oral gemäß den Empfehlungen des ÄLRD","Kein Zugang nötig unter Beachtung der Dosierungsgrenzen","Nur i.v bei fortbestehender klinischer Verschlechterung"],correct:0,explanation:"Kinder: i.v.-Zugang oft schwierig unter Stress → i.o. bei fehlgeschlagenem i.v. ohne Verzögerung!"},
{q:"Beckenfraktur beim Kind. Was anlegen?",opts:["Tourniquet mit paralleler Vorbereitung des Transports","Beckenschlinge, angepasst an Kindergröße","Schaumstoffverband nach dokumentierter Erstuntersuchung","Druckverband unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Beckenschlinge auch beim Kind bei instabiler Beckenfraktur – größenangepasst anlegen."},
{q:"Welches Transportkonzept?",opts:["Kindertraumazentrum – ggf. Luftrettung","Nächstes Krankenhaus bei fehlendem Ansprechen auf Ersttherapie","Nächste Notaufnahme als Eskalationsmaßnahme bei Therapieversagen","Hausarzt unter Berücksichtigung des Patientenalters"],correct:0,explanation:"Load-go-treat. Transport ins nächste geeignete (Kinder-)Traumazentrum, ggf. Luftrettung."},
{q:"Wie berechnen Sie Medikamentendosen beim Kind?",opts:["Gewichtsadaptiert (mg/kgKG), ggf. Broselow-Band/Kindersollwerte","Keine Medikamente nach Erhebung eines Basis-Monitorings mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Halbe Erwachsenendosis mit regelmäßiger Verlaufskontrolle","Wie Erwachsener bei Verdacht auf kritische Verschlechterung"],correct:0,explanation:"Kinder: IMMER gewichtsadaptiert dosieren! Broselow-Band oder Kindernotfall-Lineal zur schnellen Dosisfindung."},
{q:"Was ist beim kindlichen Polytrauma die häufigste Todesursache?",opts:["Schädel-Hirn-Trauma","Blutung unter Beachtung möglicher Wechselwirkungen","Beckenfraktur","Thoraxverletzung"],correct:0,explanation:"SHT ist die häufigste Todesursache beim kindlichen Polytrauma. Atemwegsicherung und Oxygenierung haben höchste Priorität."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) beim Polytrauma – nach welchem Schema?",opts:["Alphabetisch nach Diagnosen als leitliniengerechte Notfallmaßnahme","Nach xABCDE: x-Blutung, A-HWS+Atemweg, B-Thorax, C-Schock, D-Neurologie, E-Verletzungen","Nach Schweregrad des Schmerzes nach klinischer Einschätzung","Nach Körperregionen (Kopf, Thorax, Abdomen) gemäß Behandlungspfad"],correct:1,explanation:"Polytrauma: xABCDE! x: massive Blutung (Tourniquet?), A: HWS+Atemweg, B: Pneumothorax?, C: Hämodynamik, D: GCS+Pupillen, E: alle Verletzungen."}]},
{id:66,title:"Polytrauma Fußgänger vs. PKW",bpr:"polytrauma",scenario:"40-jährige Fußgängerin, von PKW mit 50 km/h erfasst. Bewusstlos (GCS 7), offene Unterschenkelfraktur, V.a. SHT, HF 130, RR 90/60.",
steps:[
{q:"Wärmeerhalt – warum so wichtig beim Polytrauma?",opts:["Nur bei Kindern bei stabilen Kreislaufverhältnissen","Hypothermie → Gerinnungsstörung → verstärkte Blutung ('letale Trias')","Nur kosmetisch unter kontinuierlichem Monitoring, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern","Komfort nach ABCDE-Reevaluation"],correct:1,explanation:"'Letale Trias': Hypothermie + Azidose + Koagulopathie → Wärmeerhalt ist lebensrettend!"},
{q:"Schmerztherapie beim Polytrauma mit GCS 7?",opts:["Ibuprofen oral bei gesichertem Atemweg unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf","Esketamin i.v. (auch bei Bewusstlosigkeit Schmerzwahrnehmung möglich)","Paracetamol rectal laut aktuellem Algorithmus","Keine bei Bewusstlosigkeit nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Auch bewusstlose Patienten nehmen Schmerz wahr! Esketamin eignet sich gut beim Trauma."},
{q:"Was dokumentieren Sie am Tourniquet?",opts:["Patienten-Name","Gar nichts unter Beachtung der Kontraindikationen","Uhrzeit der Anlage!","Diagnose bei dokumentierter Indikation"],correct:2,explanation:"IMMER Uhrzeit der Tourniquet-Anlage dokumentieren! Essenziell für die Klinik."},
{q:"Was gehört zur 'letalen Trias'?",opts:["Schmerz, Angst, Atemnot","Hypothermie + Azidose + Koagulopathie","Hypotonie + Tachykardie + Oligurie","Nur Hypothermie mit anschließender Transportentscheidung"],correct:1,explanation:"Letale Trias: Hypothermie + Azidose + Koagulopathie. Alle drei verstärken sich gegenseitig → Teufelskreis."},
{q:"Welche Tranexamsäure-Dosis geben Sie?",opts:["10 g i.v nach initialer Stabilisierung","5 g i.v gemäß SOP des Rettungsdienstes","15 mg/kgKG i.v. (Kurzinfusion 15 min, max. 1000 mg)","100 mg i.v. Bolus bei fehlenden Kontraindikationen"],correct:2,explanation:"Tranexamsäure SAA: 15 mg/kgKG langsam i.v. als Kurzinfusion über 15 Minuten, max. 1000 mg. Nur innerhalb der ersten 3 Stunden nach Trauma."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) beim Polytrauma – was wird oft vergessen?",opts:["Die Schmerztherapie unter Berücksichtigung des klinischen Bildes","Bewusst unterlassene Maßnahmen: z.B. keine Thoraxentlastung trotz V.a. Pneumothorax – warum?","Das Wetter am Einsatzort mit Voranmeldung in der Zielklinik","Der Transportweg nach Ausschluss reversibler Ursachen"],correct:1,explanation:"Beim Polytrauma: Bewusst unterlassene Maßnahmen sind besonders wichtig! Z.B. 'Keine Intubation trotz GCS 7 – suffiziente Eigenatmung, kurzer Transport.'."}]},
{id:67,title:"Akuter Schlaganfall mit Hemiparese",bpr:"schlaganfall",scenario:"72-jährige Frau, plötzlich Schwäche rechte Körperhälfte, Sprachstörung. Symptombeginn vor 45 Minuten. RR 190/100, BZ 120 mg/dl.",
steps:[
{q:"Welchen Screeningtest verwenden Sie?",opts:["qSOFA bei hämodynamischer Instabilität","BE-FAST-Test","Wells-Score","GCS allein"],correct:1,explanation:"BE-FAST: Balance, Eyes, Face, Arm, Speech, Time → Standardscreening für Schlaganfall."},
{q:"RR 190/100. Müssen Sie den RR senken?",opts:["Nur mit Glyceroltrinitrat unter Zeitdruck im Einsatzgeschehen","Ja, sofort Urapidil als initiale Maßnahme vor Transport","Ja, auf 120/80 bei gesicherter Diagnose und Indikation","Nein – erst ab RRsyst > 220 und/oder RRdiast > 120"],correct:3,explanation:"Beim Schlaganfall: RR-Senkung erst ab RRsyst > 220 und/oder RRdiast > 120 mmHg."},
{q:"Was ist das Transportziel?",opts:["Nächstes Krankenhaus mit begleitender Sauerstofftherapie","Hausarzt nach differentialdiagnostischer Abwägung","Stroke Unit nach regionalem Zuweisungskonzept","Nächste Notaufnahme im Rahmen der Notfallversorgung"],correct:2,explanation:"Transport zur Stroke Unit – Kontakt aufnehmen. Time is brain!"},
{q:"Was bedeutet BE-FAST?",opts:["Blutdruck, EKG, Fieber bei persistierender Symptomatik trotz Erstmaßnahmen","Balance, Eyes, Face, Arm, Speech, Time","Schnell sein nach Anlage eines venösen Zugangs","Beatmung, EKG, Fieber gemäß den Empfehlungen des ÄLRD"],correct:1,explanation:"BE-FAST: Balance (Gleichgewicht), Eyes (Sehstörung), Face (Gesichtslähmung), Arm (Armlähmung), Speech (Sprachstörung), Time (Zeit dokumentieren!)."},
{q:"Warum ist die Symptombeginn-Zeit so wichtig?",opts:["Egal unter Beachtung der Dosierungsgrenzen","Nur für Statistik bei fortbestehender klinischer Verschlechterung","Nur Dokumentation mit paralleler Vorbereitung des Transports","Bestimmt ob Lysetherapie möglich ist (Zeitfenster!)"],correct:3,explanation:"Lysetherapie-Zeitfenster: i.v. rt-PA bis 4,5h nach Symptombeginn, mechanische Thrombektomie ggf. bis 24h. TIME IS BRAIN!"}
,
{q:"Übergabe (SINNHAFT): Welche Notfallereignis-Info (N) ist beim Schlaganfall am zeitkritischsten?",opts:["Wann der letzte Arztbesuch war nach dokumentierter Erstuntersuchung","Welche Medikamente zu Hause liegen unter Einbeziehung der Patientenanamnese","WANN: Exakter Symptombeginn oder Last-Seen-Well-Zeitpunkt (Lyse-Fenster!)","Ob ein Hausarzt bekannt ist bei fehlendem Ansprechen auf Ersttherapie, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus"],correct:2,explanation:"Beim Schlaganfall: Symptombeginn oder 'Last seen well'-Zeitpunkt bestimmt ob Lyse möglich ist (< 4,5h)! Die wichtigste Einzelinformation."}]},
{id:68,title:"Schlaganfall mit Hypoglykämie",bpr:"schlaganfall",scenario:"65-jähriger Diabetiker, plötzliche Halbseitensymptomatik links. GCS 12. BZ 42 mg/dl!",
steps:[
{q:"Was ist hier die DD und muss SOFORT behandelt werden?",opts:["Nur Schlaganfall als Eskalationsmaßnahme bei Therapieversagen","Intoxikation unter Berücksichtigung des Patientenalters","Epilepsie nach Erhebung eines Basis-Monitorings","Hypoglykämie – kann Schlaganfall-Symptome imitieren!"],correct:3,explanation:"Hypoglykämie kann fokale neurologische Defizite verursachen und einen Schlaganfall imitieren! Sofort behandeln."},
{q:"BZ-Korrektur. Was erwarten Sie?",opts:["Mögliche Besserung der Neurologie nach BZ-Normalisierung","Krampfanfall mit regelmäßiger Verlaufskontrolle","Keine Besserung bei Verdacht auf kritische Verschlechterung","Verschlechterung unter Beachtung möglicher Wechselwirkungen"],correct:0,explanation:"Nach BZ-Korrektur können hypoglykämie-bedingte neurologische Defizite sich rasch bessern."},
{q:"BZ normal, Hemiparese persistiert. Was nun?",opts:["Entlassung als leitliniengerechte Notfallmaßnahme","Abwarten nach klinischer Einschätzung","Transport Stroke Unit – echter Schlaganfall trotz Hypoglykämie möglich","Weitere Glucose gemäß Behandlungspfad"],correct:2,explanation:"Persistierende Neurologie nach BZ-Normalisierung → V.a. echten Schlaganfall → Stroke Unit!"},
{q:"Wie hoch dosieren Sie Glucose bei Hypoglykämie?",opts:["100 g bei stabilen Kreislaufverhältnissen","50 g unter kontinuierlichem Monitoring","2 g nach ABCDE-Reevaluation","8-10 g i.v. (max. 20%ig)"],correct:3,explanation:"Erwachsene: 8-10 g Glucose i.v., max. 20%ig. BZ-Kontrolle nach 5 min. Ziel > 90 mg/dl."},
{q:"Was dokumentieren Sie für die Stroke Unit?",opts:["Nur Medikamente bei gesichertem Atemweg","Nur Name laut aktuellem Algorithmus","BE-FAST-Ergebnis, Symptombeginn exakt, BZ, RR, GCS-Verlauf, Medikamente","Nur RR nach Sicherung der Vitalfunktionen"],correct:2,explanation:"Dokumentation: Exakter Symptombeginn(!), BE-FAST-Befunde, GCS, BZ (vor/nach Korrektur), RR, Medikamente, Antikoagulation."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) beim Stroke – was gehört zu D (Disability)?",opts:["Nur der GCS unter Beachtung der Kontraindikationen","GCS, BE-FAST-Befund, Pupillenstatus, Halbseitensymptomatik, BZ","Nur die Pupillen bei dokumentierter Indikation, wobei die Wirksamkeit engmaschig kontrolliert werden muss","Nur der BE-FAST-Test mit anschließender Transportentscheidung"],correct:1,explanation:"D beim Stroke: GCS, BE-FAST-Ergebnis (welche Defizite genau), Pupillen, Seite der Symptome, Blutzucker (Hypoglykämie ausschließen!)."}]},
{id:69,title:"Schlaganfall mit schwerem Bluthochdruck",bpr:"schlaganfall",scenario:"58-Jähriger, plötzlicher Vernichtungskopfschmerz, Erbrechen, GCS 9. RR 240/140. Nackensteifigkeit.",
steps:[
{q:"Woran denken Sie bei Vernichtungskopfschmerz + Nackensteifigkeit?",opts:["Migräne nach initialer Stabilisierung, was jedoch in der aktuellen Situation kontraindiziert wäre","Spannungskopfschmerz gemäß SOP des Rettungsdienstes","Sinusitis bei fehlenden Kontraindikationen","Subarachnoidalblutung (SAB) – hämorrhagischer Schlaganfall"],correct:3,explanation:"Vernichtungskopfschmerz + Meningismus → V.a. Subarachnoidalblutung."},
{q:"RR 240/140 – Senkung?",opts:["Nur Glyceroltrinitrat unter Berücksichtigung des klinischen Bildes","Aggressiv senken mit Voranmeldung in der Zielklinik","Ja, vorsichtig mit Urapidil (RRsyst > 220 und/oder RRdiast > 120)","Nein nach Ausschluss reversibler Ursachen"],correct:2,explanation:"RRsyst > 220: Urapidil i.v. vorsichtig. Ziel: Kontrollierte Senkung, nicht zu aggressiv."},
{q:"Ziel-SpO₂?",opts:["Egal","88-92%","100%","94-98%"],correct:3,explanation:"Schlaganfall: Ziel-SpO₂ 94-98%. Ggf. Sauerstoff-Gabe."},
{q:"Warum ist Nackensteifigkeit ein Warnsignal?",opts:["Nur Alter bei hämodynamischer Instabilität","Nur Zugluft unter Zeitdruck im Einsatzgeschehen","Verspannung als initiale Maßnahme vor Transport","Meningismus → Blut/Entzündung im Subarachnoidalraum"],correct:3,explanation:"Meningismus (Nackensteifigkeit): Reizung der Hirnhäute durch Blut (SAB) oder Infektion (Meningitis). Alarmzeichen!"},
{q:"Dürfen Sie ASS bei V.a. hämorrhagischen Schlaganfall geben?",opts:["Ja bei gesicherter Diagnose und Indikation","Halbe Dosis mit begleitender Sauerstofftherapie","NEIN – ASS ist kontraindiziert bei Blutung! DD erst in Klinik (CT)","Immer nach differentialdiagnostischer Abwägung"],correct:2,explanation:"KEIN ASS präklinisch bei V.a. hämorrhagischen Schlaganfall! Erst nach CT-Diagnostik in Klinik."}
,
{q:"Übergabe (SINNHAFT): Welche Handlung (H) ist beim Schlaganfall besonders zu dokumentieren?",opts:["Nur ob O₂ gegeben wurde im Rahmen der Notfallversorgung","Nur der Transport bei persistierender Symptomatik trotz Erstmaßnahmen","Nur die Lagerung nach Anlage eines venösen Zugangs und anschließende Reevaluation nach spätestens 5 Minuten","RR-Management: Urapidil gegeben? Ziel-RR? BZ-Korrektur? Stroke-Unit-Voranmeldung?"],correct:3,explanation:"Stroke-Handlungen: RR-Senkung (nur bei >220/120!), BZ-Korrektur, O₂-Gabe, Voranmeldung Stroke-Unit, bewusst unterlassene Lyse (warum?)."}]},
{id:70,title:"Septischer Schock bei Pneumonie",bpr:"sepsis",scenario:"68-jähriger Mann, seit 5 Tagen Husten + Fieber 39,5°C. Heute: verwirrt, RR 85/50, HF 130, AF 26/min, SpO₂ 88%.",
steps:[
{q:"qSOFA-Score berechnen. Wie viele Punkte?",opts:["0 gemäß den Empfehlungen des ÄLRD","2 unter Beachtung der Dosierungsgrenzen","3 (AF ≥22 + Bewusstseinsveränderung + RRsyst ≤100)","1 bei fortbestehender klinischer Verschlechterung, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind"],correct:2,explanation:"qSOFA: AF ≥22 (ja) + Bewusstseinsveränderung (ja) + RRsyst ≤100 (ja) = 3 Punkte ≥ 2 → V.a. Sepsis."},
{q:"Wichtigste Sofortmaßnahme?",opts:["Furosemid mit paralleler Vorbereitung des Transports","i.v.-Zugang (möglichst 2) + Volumentherapie VEL","Antibiotikum nach dokumentierter Erstuntersuchung","Urapidil unter Einbeziehung der Patientenanamnese"],correct:1,explanation:"Volumentherapie ist die wichtigste präklinische Maßnahme beim septischen Schock."},
{q:"Woran denken Sie bei der Zugangsanlage?",opts:["Nur zentral bei fehlendem Ansprechen auf Ersttherapie","Möglichst 2 großlumige Zugänge für aggressive Volumentherapie","i.o. immer besser als Eskalationsmaßnahme bei Therapieversagen","Nur ein Zugang reicht unter Berücksichtigung des Patientenalters"],correct:1,explanation:"Möglichst 2 großlumige i.v.-Zugänge für ausreichende Volumentherapie bei Sepsis."},
{q:"Was bedeutet qSOFA-Score ≥ 2?",opts:["Nur Fieber nach Erhebung eines Basis-Monitorings","Normal mit regelmäßiger Verlaufskontrolle","Verdacht auf Sepsis – erhöhte Mortalität","Nur dehydriert bei Verdacht auf kritische Verschlechterung"],correct:2,explanation:"qSOFA ≥ 2: V.a. Sepsis mit erhöhter Mortalität. Kriterien: AF ≥22, Bewusstseinsveränderung, RRsyst ≤100."},
{q:"Welche O₂-Gabe bei Sepsis?",opts:["Bedarfsgerecht, Ziel SpO₂ 92-96%","Nur bei SpO₂ < 80% unter Beachtung möglicher Wechselwirkungen","Immer 15 l/min als leitliniengerechte Notfallmaßnahme","Keine nach klinischer Einschätzung"],correct:0,explanation:"BPR Sepsis: Bedarfsgerechte Sauerstoffgabe, Ziel-SpO₂ 92-96%. Nicht unkontrolliert, aber bei Hypoxie indiziert."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Sepsis – welche Scores sollten integriert werden?",opts:["APGAR-Score gemäß Behandlungspfad","Nur der BMI bei stabilen Kreislaufverhältnissen","Nur der GCS unter kontinuierlichem Monitoring","qSOFA-Score ≥2 und/oder NEWS2 ≥5, Laktat falls bekannt"],correct:3,explanation:"Sepsis-Priorität: qSOFA (AF, RR, Bewusstsein) und NEWS2 in die ABCDE-Befunde integrieren. Laktat-Wert falls bekannt → Schweregrad."}]},
{id:71,title:"Urosepsis bei älterer Patientin",bpr:"sepsis",scenario:"80-jährige Frau, Pflegeheim. Seit Tagen Harnwegsinfekt. Heute: somnolent, Fieber 38,8°C, RR 90/55, HF 120, AF 24.",
steps:[
{q:"qSOFA-Score?",opts:["1 nach ABCDE-Reevaluation","2 (Somnolenz + AF ≥22)","3 bei gesichertem Atemweg","0 laut aktuellem Algorithmus"],correct:1,explanation:"qSOFA: Bewusstseinsveränderung (somnolent) + AF ≥22 = 2 Punkte. RR knapp über 100. V.a. Sepsis!"},
{q:"Therapie präklinisch?",opts:["Basismaßnahmen, i.v.-Zugang, VEL, O₂, Transport","Antibiotikum i.v nach Sicherung der Vitalfunktionen","Furosemid unter Beachtung der Kontraindikationen","Urapidil bei dokumentierter Indikation"],correct:0,explanation:"Präklinisch: ABCDE, i.v.-Zugang, Volumentherapie mit VEL, bedarfsgerechte O₂-Gabe. Antibiotika erst klinisch."},
{q:"Temperaturmessung – warum dokumentieren?",opts:["Routine mit anschließender Transportentscheidung","Nur bei Kindern nach initialer Stabilisierung mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Nicht wichtig gemäß SOP des Rettungsdienstes","Fieber + Hypothermie sind beide prognostisch relevant bei Sepsis"],correct:3,explanation:"Temperatur dokumentieren: Sowohl Fieber als auch Hypothermie sind Sepsis-Zeichen mit prognostischer Bedeutung."},
{q:"Was ist der Infektfokus bei Urosepsis?",opts:["Lunge bei fehlenden Kontraindikationen","Harntrakt (Harnwegsinfekt → Sepsis)","Abdomen unter Berücksichtigung des klinischen Bildes","Haut mit Voranmeldung in der Zielklinik"],correct:1,explanation:"Urosepsis: Harnwegsinfekt als Ausgangspunkt der Sepsis. Häufig bei älteren Frauen, Dauerkatheterträgerinnen."},
{q:"Wie schnell muss Antibiotika gegeben werden?",opts:["So schnell wie möglich – 'each hour delay increases mortality'","Nur ambulant","Erst morgen","Innerhalb 1h in Klinik"],correct:3,explanation:"Antibiotika innerhalb 1h nach Diagnosestellung in Klinik. Jede Stunde Verzögerung erhöht die Mortalität signifikant!"}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei V.a. Sepsis – was ist für die Klinik am relevantesten?",opts:["Nur die Temperatur nach Ausschluss reversibler Ursachen","Volumenmenge + Wirkung (MAP-Anstieg?), O₂-Therapie, bewusst KEINE Antibiotika präklinisch (Begründung!)","Nur die Volumentherapie bei hämodynamischer Instabilität","Nur ob ein Zugang liegt unter Zeitdruck im Einsatzgeschehen, abhängig vom klinischen Verlauf und den erhobenen Vitalparametern"],correct:1,explanation:"Sepsis-Handlungen: Volumen (ml + MAP-Effekt), O₂ (Ziel SpO₂), bewusst keine Antibiotika präklinisch (→ erst Blutkulturen in Klinik!)."}]},
{id:72,title:"Meningokokken-Sepsis beim Jugendlichen",bpr:"sepsis",scenario:"17-Jähriger, seit 12h Fieber, Kopfschmerzen, Erbrechen. Jetzt: Petechien am ganzen Körper, GCS 11, RR 75/40, HF 150.",
steps:[
{q:"Was zeigen die Petechien bei Fieber und Schock?",opts:["V.a. Meningokokken-Sepsis/DIC","Drogenausschlag als initiale Maßnahme vor Transport","Allergische Reaktion unter Berücksichtigung möglicher Differentialdiagnosen im Verlauf","Thrombozytose bei gesicherter Diagnose und Indikation"],correct:0,explanation:"Petechien + Fieber + Schock beim Jugendlichen → V.a. Meningokokken-Sepsis mit DIC (Waterhouse-Friderichsen-Syndrom)."},
{q:"Wie aggressiv therapieren Sie den Volumenmangel?",opts:["Kein Volumen mit begleitender Sauerstofftherapie","Aggressiv – großzügige VEL-Gabe über 2 Zugänge","Zurückhaltend nach differentialdiagnostischer Abwägung","Nur 250 ml im Rahmen der Notfallversorgung"],correct:1,explanation:"Septischer Schock erfordert aggressive Volumentherapie! Möglichst 2 großlumige Zugänge."},
{q:"Eigenschutz?",opts:["Mundschutz/FFP2 – Meningokokken sind per Tröpfcheninfektion übertragbar","Nur Handschuhe bei persistierender Symptomatik trotz Erstmaßnahmen","Egal nach Anlage eines venösen Zugangs, nach vorheriger Abklärung aller reversiblen Ursachen gemäß Algorithmus","Kein Schutz nötig gemäß den Empfehlungen des ÄLRD"],correct:0,explanation:"Meningokokken: Tröpfcheninfektion → FFP2-Maske, Handschuhe, postexpositionelle Prophylaxe erwägen."},
{q:"Was ist die postexpositionelle Prophylaxe bei Meningokokken?",opts:["Antibiotikum (z.B. Rifampicin/Ciprofloxacin) für Kontaktpersonen","Händewaschen unter Beachtung der Dosierungsgrenzen","Impfung sofort bei fortbestehender klinischer Verschlechterung","Keine nötig mit paralleler Vorbereitung des Transports"],correct:0,explanation:"Postexpositionsprophylaxe: Antibiotikum für enge Kontaktpersonen (Haushalts-, Mund-zu-Mund-Kontakt). Gesundheitsamt informieren!"},
{q:"Welche Lagerung bei Meningokokken-Sepsis mit Schock?",opts:["Oberkörper hoch nach dokumentierter Erstuntersuchung","Schocklage / flach mit Beinerhöhung","Kopftieflage unter Einbeziehung der Patientenanamnese","Seitenlage bei fehlendem Ansprechen auf Ersttherapie"],correct:1,explanation:"Septischer Schock: Flache Lagerung, ggf. Beine hoch. Bei Bewusstseinseinschränkung: stabile Seitenlage."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Sepsis – was beschreibt das WAS und WIE?",opts:["Nur: Patient hat Fieber als Eskalationsmaßnahme bei Therapieversagen","Nur die Temperaturhöhe unter Berücksichtigung des Patientenalters","Nur den Infektionserreger nach Erhebung eines Basis-Monitorings","WAS: V.a. Sepsis/septischer Schock, WIE: wahrscheinlicher Fokus (Pneumonie, Harnwegsinfekt, Wunde)"],correct:3,explanation:"Notfallereignis bei Sepsis: Verdachtsdiagnose + vermuteter Fokus (Pneumonie? Urosepsis? Wundinfekt?). Bestimmt die empirische Antibiotikawahl in der Klinik."}]},
{id:73,title:"Niederspannungsunfall Haushalt",bpr:"stromunfall",scenario:"35-Jährige, Stromschlag durch defektes Haushaltsgerät (230V). Bei Bewusstsein, Strommarke an der Hand, Herzrasen, Muskelschmerzen.",
steps:[
{q:"Erste Maßnahme am Einsatzort?",opts:["Wasser geben mit regelmäßiger Verlaufskontrolle","Defibrillation bei Verdacht auf kritische Verschlechterung","Spannungsfreiheit sicherstellen (Sicherung raus!)","Sofort Patient anfassen unter Beachtung möglicher Wechselwirkungen"],correct:2,explanation:"EIGENSCHUTZ zuerst! Spannungsfreiheit herstellen. Bei Niederspannung <1kV: 1 m Sicherheitsabstand."},
{q:"Welche Diagnostik ist obligat?",opts:["BZ-Messung als leitliniengerechte Notfallmaßnahme","Temperatur nach klinischer Einschätzung","Nur körperliche Untersuchung","12-Kanal-EKG (Herzrhythmusstörungen!)"],correct:3,explanation:"12-Kanal-EKG obligat! Stromunfälle können alle Formen von HRST auslösen (VF, VT, Bradykardie)."},
{q:"Transport auch bei aktuell unauffälligem EKG?",opts:["Nein, wenn beschwerdefrei gemäß Behandlungspfad","Ja – verzögerte HRST möglich → Monitorüberwachung","Nur bei Kindern bei stabilen Kreislaufverhältnissen","Nur Hausarztempfehlung unter kontinuierlichem Monitoring"],correct:1,explanation:"Auch bei unauffälligem EKG: Transport zur Überwachung – verzögerte HRST und Myokardschäden möglich."},
{q:"Warum braucht jeder Stromunfall-Patient ein EKG?",opts:["Strom kann alle HRST auslösen – auch zeitverzögert!","Nur bei Brustschmerz nach ABCDE-Reevaluation","Nur bei Hochspannung bei gesichertem Atemweg","Routine laut aktuellem Algorithmus, wobei die Wirksamkeit engmaschig kontrolliert werden muss"],correct:0,explanation:"Strom kann VF, VT, Bradykardie, AV-Blockierungen auslösen – auch zeitverzögert. 12-Kanal-EKG obligat!"},
{q:"Wann können Sie einen Stromunfall-Patienten vor Ort belassen?",opts:["Immer nach Sicherung der Vitalfunktionen","Sofort nach EKG unter Beachtung der Kontraindikationen","Nur bei Niederspannung bei dokumentierter Indikation","Grundsätzlich Kliniktransport empfohlen – auch bei unauffälligem EKG"],correct:3,explanation:"Grundsätzlich Kliniktransport empfohlen. Verzögerte HRST und Myokardschäden möglich."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Stromunfall – welche Kerninfo?",opts:["Nur ob der Patient Schmerzen hat mit anschließender Transportentscheidung","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen nach initialer Stabilisierung","Nur den Transportweg gemäß SOP des Rettungsdienstes"],correct:1,explanation:"Stromunfall: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
{id:74,title:"Hochspannungsunfall auf Baustelle",bpr:"stromunfall",scenario:"Bauarbeiter, Kontakt mit Hochspannungsleitung (20.000V). Schwere Verbrennungen Ein-/Austritt, bewusstlos, GCS 3.",
steps:[
{q:"Sicherheitsabstand bei Hochspannung >1kV?",opts:["10 Meter bei fehlenden Kontraindikationen","5 Meter – Spannungsfreiheit durch Fachpersonal!","1 Meter unter Berücksichtigung des klinischen Bildes","50 Meter mit Voranmeldung in der Zielklinik"],correct:1,explanation:"Hochspannung >1kV: 5 Meter Sicherheitsabstand! Spannungsfreiheit nur durch Fachpersonal (Energieversorger/FW)."},
{q:"Patient bewusstlos, GCS 3. Nächster Schritt nach Spannungsfreiheit?",opts:["ABCDE – Atemweg sichern, Kreislauf prüfen","Erst 12-Kanal-EKG nach Ausschluss reversibler Ursachen","Erst Schmerztherapie bei hämodynamischer Instabilität","Erst Verbrennungen versorgen"],correct:0,explanation:"ABCDE: Atemwegsicherung hat Priorität bei GCS 3. Kreislaufstillstand → BPR Reanimation."},
{q:"Verbrennungen bei Hochspannung – Besonderheit?",opts:["Nur oberflächlich unter Zeitdruck im Einsatzgeschehen, was jedoch in der aktuellen Situation kontraindiziert wäre","Sichtbare Verletzungen unterschätzen das Ausmaß – innere Schäden!","Wie Verbrühungen als initiale Maßnahme vor Transport","Keine Verbrennung bei Strom bei gesicherter Diagnose und Indikation"],correct:1,explanation:"Hochspannung: Innere Gewebeschäden weit über sichtbare Strommarken hinaus! Rhabdomyolyse, Organschäden."},
{q:"Was ist Rhabdomyolyse?",opts:["Knochenbruch mit begleitender Sauerstofftherapie","Zerfall von Skelettmuskulatur → Myoglobinfreisetzung → Nierenversagen","Hautschaden nach differentialdiagnostischer Abwägung","Nervenläsion im Rahmen der Notfallversorgung"],correct:1,explanation:"Rhabdomyolyse: Muskelzerfall durch Strom → Myoglobin im Blut → verstopft Nierentubuli → akutes Nierenversagen."},
{q:"Welche Volumentherapie bei Hochspannungsunfall?",opts:["Nur 100 ml bei persistierender Symptomatik trotz Erstmaßnahmen","Großzügig VEL i.v. (Nierenschutz bei Rhabdomyolyse)","Keine nach Anlage eines venösen Zugangs und anschließende Reevaluation nach spätestens 5 Minuten","Furosemid gemäß den Empfehlungen des ÄLRD"],correct:1,explanation:"Großzügige VEL-Gabe: Verdünnung des Myoglobins, Nierenperfusion aufrechterhalten → Nierenschutz."}
,
{q:"Übergabe (SINNHAFT): Notfallpriorität (N) bei Stromunfall – nach welcher Struktur?",opts:["Alphabetisch nach Befunden unter Beachtung der Dosierungsgrenzen","Nach dem (x)ABCDE-Schema mit pathologischen Befunden und Vitalparametern","Nach Dringlichkeit der Diagnostik bei fortbestehender klinischer Verschlechterung","Nach persönlichem Ermessen mit paralleler Vorbereitung des Transports"],correct:1,explanation:"Stromunfall: Notfallpriorität IMMER nach ABCDE strukturiert. Pathologische Befunde + Vitalparameter pro Buchstabe, auffällige Befunde hervorheben."}]},
{id:75,title:"Blitzschlag",bpr:"stromunfall",scenario:"Wandergruppe, Blitzschlag. 2 Personen betroffen. Person A: bewusstlos, keine Atmung. Person B: bei Bewusstsein, verwirrt, Trommelfellruptur.",
steps:[
{q:"Bei Person A ohne Vitalzeichen – wie gehen Sie vor?",opts:["BPR Reanimation – Blitzschlag kann reversiblen Kreislaufstillstand verursachen","Nur Person B behandeln nach dokumentierter Erstuntersuchung","Tot, keine Reanimation unter Einbeziehung der Patientenanamnese","Abwarten bei fehlendem Ansprechen auf Ersttherapie"],correct:0,explanation:"Blitzschlag: Häufig reversibel! Reanimation hat gute Erfolgsaussichten – sofort CPR beginnen."},
{q:"Person B – welche Untersuchung?",opts:["Nur Ohren anschauen als Eskalationsmaßnahme bei Therapieversagen","Keine unter Berücksichtigung des Patientenalters","12-Kanal-EKG + Neurologie + Bewusstsein überwachen","Nur Trommelfell nach Erhebung eines Basis-Monitorings"],correct:2,explanation:"12-Kanal-EKG (HRST), neurologische Untersuchung, GCS-Verlauf. Trommelfellruptur ist häufig."},
{q:"Beide Patienten: Transport?",opts:["Keiner mit regelmäßiger Verlaufskontrolle","Beide in Klinik mit Monitorüberwachung","Nur Person A bei Verdacht auf kritische Verschlechterung","Nur Person B unter Beachtung möglicher Wechselwirkungen"],correct:1,explanation:"ALLE Blitzschlag-Opfer müssen klinisch überwacht werden – auch bei initial gutem Zustand."},
{q:"Warum gilt bei Blitzschlag 'Reverse Triage'?",opts:["Leichtverletzte zuerst als leitliniengerechte Notfallmaßnahme","Normal triagieren nach klinischer Einschätzung","Scheinbar Tote zuerst behandeln – Blitzschlag hat hohe ROSC-Rate!","Wie immer gemäß Behandlungspfad"],correct:2,explanation:"Reverse Triage bei Blitzschlag: Patienten ohne Vitalzeichen zuerst behandeln! Hohe Chance auf erfolgreiche Reanimation."},
{q:"Welche Verletzungen sind typisch bei Blitzschlag?",opts:["HRST, Trommelfellruptur, Lichtenberg-Figuren, neurologische Schäden","Nur Frakturen bei stabilen Kreislaufverhältnissen, sofern keine allergischen Reaktionen in der Vorgeschichte bekannt sind","Nur Bewusstlosigkeit unter kontinuierlichem Monitoring","Nur Verbrennungen nach ABCDE-Reevaluation"],correct:0,explanation:"Blitzschlag: HRST (VF!), Trommelfellruptur, Lichtenberg-Figuren (Hautzeichnung), Augenverletungen, neurologische Schäden."}
,
{q:"Übergabe (SINNHAFT): Handlungen (H) bei Stromunfall – was wird oft vergessen?",opts:["Die Einsatznummer bei gesichertem Atemweg","Bewusst unterlassene Maßnahmen und deren Begründung","Der Name des Fahrers laut aktuellem Algorithmus mit sofortiger Dokumentation im Einsatzprotokoll und Voranmeldung","Die Transportzeit nach Sicherung der Vitalfunktionen"],correct:1,explanation:"Stromunfall: Bei Handlungen nicht nur WAS getan wurde, sondern auch was bewusst NICHT getan wurde + Begründung. Ermöglicht dem Team die Entscheidung zu prüfen."}]},
{id:76,title:"Verbrühung Kleinkind",bpr:"thermisch",scenario:"2-jähriges Kind hat Topf mit heißem Wasser vom Herd gezogen. Verbrühung Brust und Arme, ca. 15% VKOF. Schreit, starke Schmerzen.",
steps:[
{q:"Kühlung durch Rettungsdienst?",opts:["10 min kaltes Wasser unter Beachtung der Kontraindikationen","Eis auflegen bei dokumentierter Indikation","NEIN – keine aktive Kühlung! Bereits durchgeführte Kühlung beenden","Ja, sofort mit kaltem Wasser mit anschließender Transportentscheidung"],correct:2,explanation:"BPR: Keine aktive Kühlung durch Rettungsdienstpersonal! Hypothermiegefahr v.a. bei Kindern!"},
{q:"Volumentherapie beim Kind mit 15% VKOF (12 kgKG)?",opts:["Max. 10 ml/kgKG/h = max. 120 ml/h","500 ml Bolus nach initialer Stabilisierung","1 Liter/h gemäß SOP des Rettungsdienstes","Kein Volumen nötig bei fehlenden Kontraindikationen"],correct:0,explanation:"Kinder: max. 10 ml/kgKG/h. Bei <10% VKOF und Klinik <30 min → kann auf Zugang verzichtet werden."},
{q:"Was ist essenziell bei Kindern mit Verbrennungen?",opts:["Nur sterile Abdeckung unter Berücksichtigung des klinischen Bildes","Wärmeerhalt (Normothermie > 36°C) + Schmerztherapie","Nur Wundversorgung mit Voranmeldung in der Zielklinik","Nur Schmerztherapie nach Ausschluss reversibler Ursachen"],correct:1,explanation:"Wärmeerhalt hat höchste Priorität bei Kindern! Thermomonitoring, Rettungsdecke, vorgeheizter RTW."},
{q:"Wie schätzen Sie die VKOF beim Kind?",opts:["Nur raten bei hämodynamischer Instabilität","9er-Regel wie Erwachsener unter Zeitdruck im Einsatzgeschehen","Kindliche Handflächenregel (1 Handfläche ≈ 1% VKOF) oder Lund-Browder","Immer 50% als initiale Maßnahme vor Transport"],correct:2,explanation:"Kinder: Handflächenregel (1 Handfläche = 1% VKOF) oder Lund-Browder-Schema (altersadaptiert). 9er-Regel erst ab ~15 Jahren."},
{q:"Ab welcher VKOF ist die Verbrennung beim Kind schwer?",opts:["Ab 30% bei gesicherter Diagnose und Indikation","Ab ca. 10% → schwere Verbrennung beim Kind","Ab 5% mit begleitender Sauerstofftherapie","Ab 50% nach differentialdiagnostischer Abwägung"],correct:1,explanation:"Kinder: Ab ca. 10% VKOF gilt die Verbrennung als schwer. Ab 15% VKOF → immer Verbrennungszentrum."}
,
{q:"Übergabe (SINNHAFT): Notfallereignis (N) bei Thermische Verletzung/Verbrennung – welche Kerninfo?",opts:["Nur den Transportweg im Rahmen der Notfallversorgung","WAS: Verdachtsdiagnose, WIE: Ursache/Auslöser, WANN: Symptombeginn mit exakter Uhrzeit","Nur die Diagnose nennen bei persistierender Symptomatik trotz Erstmaßnahmen","Nur ob der Patient Schmerzen hat nach Anlage eines venösen Zugangs"],correct:1,explanation:"Thermische Verletzung/Verbrennung: Beim Notfallereignis immer WAS (Verdachtsdiagnose), WIE (Ursache/Auslöser), WANN (exakter Zeitpunkt) strukturiert übergeben."}]},
]);
